window.GEPAED_ARTIGOS = [{"ano":2026,"titulo":"Contexto Social e Conhecimentos Declarativos de Ingressantes no Curso de Física-LicenciaturaSocial Context and Declarative Knowledge of New Students in the Physics Undergraduate Program","autores":"Kátia Calligaris Rodrigues","autores_todos":[],"estudantes":[],"periodico":"REVISTA DE ENSEÑANZA DE LA FÍSICA","qualis":"A1","area":"Educação","temas":["Metacognição e Autorregulação","Formação de Professores","Avaliação e Trajetórias","Ensino de Ciências e Matemática"],"disciplina":"Física","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://doi.org/10.55767/2451.6007.v38.n1.52397","doi":"10.55767/2451.6007.v38.n1.52397","resumo":"O presente trabalho apresenta uma análise diagnóstica inicial sobre o perfil de estudantes ingressantes no curso de Licenciatura em Física, com foco em seu contexto físico e social de estudo e seu conhecimento declarativo sobre estratégias cognitivas simples. A pesquisa parte da constatação de que muitos desses estudantes enfrentam dificuldades na resolução de problemas de Física, o que contribui para elevadas taxas de retenção e evasão, especialmente nos primeiros semestres do curso. Justifica-se, portanto, a importância de compreender os conhecimentos declarativos o contexto físico e social em que esses estudantes apresentam ao ingressar no curso, a fim de subsidiar intervenções pedagógicas e promover o desenvolvimento da autorregulação da aprendizagem (ARA). A metodologia adotada envolveu a aplicação do Formulário Eletrônico de Análise Diagnóstica da Autorregulação da Aprendizagem (ADARA), composto por questões abertas e fechadas distribuídas em 4 blocos principais. O instrumento foi respondido por 38 estudantes na primeira semana do curso, e permitiu levantar dados sobre o ambiente físico de estudo, tempo disponível para estudar, organização pessoal e domínio de estratégias cognitivas. Para fins deste trabalho, foram selecionadas quatro perguntas fechadas consideradas mais representativas, além da análise do domínio declarado e observado sobre estratégias básicas de resolução de problemas."},{"ano":2026,"titulo":"Realização de tipagem sanguínea em alunos de terceiro ano de escola do município de Igarassu/PE: relato de experiência de extensionistas","autores":"José Antônio Bezerra de Oliveira","autores_todos":[],"estudantes":[],"periodico":"REVISTA EXTENSÃO","qualis":"A4","area":"Educação","temas":"Ensino de Ciências e Matemática","disciplina":"Biologia","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://revista.unitins.br/index.php/extensao/article/view/10931","doi":"","resumo":""},{"ano":2025,"titulo":"Clima escolar e o impacto de intervenções pedagógicas na mediação docente, segurança emocional e aprendizagem","autores":"Gabriel Fortes","autores_todos":["Rita Tayná Guimarães","Pedro Henrique Gomes","Angelina Vasconcelos","Gabriel Fortes"],"estudantes":[],"periodico":"REVISTA EDUCAÇÃO & ENSINO - ISSN 2594-4444","qualis":"B1","area":"Psicologia","temas":["Aprendizagem Significativa","Formação de Professores","Psicologia e Subjetividade","Avaliação e Trajetórias"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://doi.org/10.71136/ree.v9i1.853","doi":"10.71136/ree.v9i1.853","resumo":"O artigo analisa como intervenções pedagógicas e estruturais influenciam o clima escolar, com foco no desenvolvimento socioemocional e acadêmico de alunos do Ensino Fundamental I. A partir de um relato de experiência, descrevem-se estratégias como reorganização do espaço físico, escuta ativa, ensino de habilidades socioemocionais e formação docente. Os resultados evidenciam redução de conflitos, aumento do engajamento e melhoria no desempenho escolar. Também é proposto um protocolo de intervenção estruturado em níveis (individual, grupal e coletivo), com metas de curto e longo prazo. A análise reforça que vínculos afetivos positivos, segurança emocional e cooperação entre educadores, alunos e famílias são essenciais para uma aprendizagem significativa. Conclui-se que intervenções planejadas, integradas ao cotidiano escolar, promovem um clima favorável ao bem-estar e ao sucesso acadêmico."},{"ano":2025,"titulo":"Conflictos y articulaciones sobre las formas de hacer música: Una aproximación cualitativa a la subjetividad de músicos independientes","autores":"Gabriel Fortes","autores_todos":[],"estudantes":[],"periodico":"APOSTA: REVISTA DE CIENCIAS SOCIALES","qualis":"A2","area":"Psicologia","temas":"Psicologia e Subjetividade","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://dialnet.unirioja.es/servlet/articulo?codigo=10443834","doi":"","resumo":""},{"ano":2025,"titulo":"Ensino Fundamental, Ecologia e diversidade: uma vivência no estágio","autores":"Tais de Oliveira Silva","autores_todos":[],"estudantes":[],"periodico":"","qualis":"B1","area":"Educação","temas":"Formação de Professores","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://doi.org/10.21680/2763-6488.2025V7N1ID40909.","doi":"10.21680/2763-6488.2025V7N1ID40909.","resumo":""},{"ano":2025,"titulo":"Identificação de autorregulação da aprendizagem em formulário de hábitos de estudo do ENEM","autores":"Kátia Calligaris Rodrigues","autores_todos":[],"estudantes":[],"periodico":"RENOTE. REVISTA NOVAS TECNOLOGIAS NA EDUCAÇÃO","qualis":"A4","area":"Educação","temas":"Metacognição e Autorregulação","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://seer.ufrgs.br/renote/article/view/149299","doi":"","resumo":""},{"ano":2025,"titulo":"Living in music: The many paths to the possible and the inescapable form-of-life of independent musicians","autores":"Gabriel Fortes","autores_todos":["Mauricio Toval-Gajardo","Gabriel Fortes"],"estudantes":[],"periodico":"POSSIBILITY STUDIES & SOCIETY","qualis":"B2","area":"Psicologia","temas":"Psicologia e Subjetividade","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1177/27538699251337730","doi":"10.1177/27538699251337730","resumo":"This study examines how independent musicians inhabit and persist in music as an inescapable form-of-life, shaping and sustaining themselves through creative engagement with the “possible.” Drawing on Vlad Glăveanu’s concept of the “possible” and Giorgio Agamben’s notion of “form-of-life,” we explore how music becomes more than a career for these artists—it forms the core of their existence, structuring identity, resilience, and purpose. Therefore, we aim to understand how tensions, restrictions, obstacles and other forms of semiotic mediation guide how a possible becomes “the” only possible for these musicians. Using a multiple case study design, we conducted semi-structured interviews and participant observations with seven independent musicians, each with over a decade of creative experience. Dialogical discourse analysis was employed to assess different forms of engagement with musical work. These themes illustrate how musicians sustain their practice not just economically but as an essential aspect of life. Our findings suggest that musicians inhabit music through multiple, interconnected dimensions, affirming it as an existential necessity. This study highlights the formation of the inescapable possibility of being a musician for our participants."},{"ano":2025,"titulo":"Obstáculos educacionais entre estudantes brasileiros: desvendando barreiras a partir de um modelo psicoeducacional","autores":"Gabriel Fortes","autores_todos":["Gleidson Diego Lopes Loureto","Gabriel Fortes de Macedo","María Ángela Mattar Yunes","Leonardo Brandão","Ig Ibert Bittencourt"],"estudantes":[],"periodico":"AVALIAÇÃO PSICOLÓGICA","qualis":"A1","area":"Educação","temas":["Políticas e Equidade Educacional","Avaliação e Trajetórias"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://dialnet.unirioja.es/servlet/oaiart?codigo=10674186","doi":"","resumo":"O presente artigo objetivou avaliar os impactos de contextos de baixa equidade educacional em variáveis escolares e individuais de estudantes brasileiros. Para tanto, utilizou-se um modelo psicoeducacional que equaciona as experiências dos estudantes e que mensura as dimensões escolares e individuais desse fenômeno. A amostra foi composta por estudantes brasileiros da Educação Básica (n=646). Os participantes foram comparados em termos de gênero, cor/raça, condição socioeconômica e série escolar nas dimensões escolares e individuais da equidade através do Instrumento de Avaliação da Equidade Educacional (IAE-E; total de 18 facetas). Em conjunto, os resultados convergem em parte com evidências anteriores, ratificam o impacto de elementos interseccionais para grupos marginalizados e levantam insights sobre a dinamicidade de obstáculos enfrentados pelos estudantes. Os resultados são discutidos sob uma perspectiva interseccional visando subsidiar intervenções que dialoguem com questões como a diversidade e a justiça social visando dirimir a perpetuação de desigualdades nos sistemas de ensino."},{"ano":2025,"titulo":"Perceptions of Pre-Service Teachers in a Pedagogical Residency Program Teaching Physics Using a PBL Approach","autores":"Kátia Calligaris Rodrigues","autores_todos":["Manoel Felix","Thaynara Sabrina Guedes da Silva","Kátia Calligaris Rodrigues"],"estudantes":[],"periodico":"EDUCATION SCIENCES","qualis":"C","area":"Educação","temas":["Formação de Professores","Metodologias Ativas e Tecnologia"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.3390/educsci15091190","doi":"10.3390/educsci15091190","resumo":"Background: Unlike medical training, science teacher training in Brazil does not include PBL as a curricular methodology. However, there is a Pedagogical Residency Program (PRP) that allows teaching experiences that are different from those provided in the undergraduate course. Thus, in this research, we propose a formative intervention in PBL for scholarship holders in the Pedagogical Residency Program (hereinafter Residents), aiming to answer the following question: “What are the perceptions of pre-service teachers about the planning, implementation, and evaluation of a PBL intervention in physics teaching?”. Methods: Five Residents taught an elective course specially designed for the application of PBL to teach secondary school physics. The training of the Residents in PBL occurred almost simultaneously with the offering of the elective subject. To reveal their perceptions, we collected Residents’ teaching plans, problem scenarios, and reflective analyses. Results: The results demonstrate that the Residents encountered several difficulties in developing and implementing the PBL methodology when teaching physics. Regarding development, the difficulties lie in coherently aligning the learning objectives with the highly complex active methodology of PBL. In addition, another clear difficulty is developing a problem situation appropriate to the knowledge that one wishes to develop. During the intervention, the Residents realized how difficult it is to implement PBL to allow st"},{"ano":2025,"titulo":"Petroflex: FlexQuest para o ensino de Ciências no contexto do derramamento de óleo nas praias brasileiras","autores":"José Antônio Bezerra de Oliveira","autores_todos":["Bárbara Lúcia de Oliveira da Silva","José Antônio  Bezerra de Oliveira","Kátia Aparecida da Silva Aquino"],"estudantes":[],"periodico":"ENSINO DE CIÊNCIAS E TECNOLOGIA EM REVISTA","qualis":"A4","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo","Educação Ambiental","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://doi.org/10.31512/encitec.v16i1.2164","doi":"10.31512/encitec.v16i1.2164","resumo":"Este estudo objetivou desenvolver e aplicar uma FlexQuest, denominada PetroFlex, voltada para o estudo do desastre do derramamento de óleo nas praias brasileiras em 2019. A pesquisa, de natureza aplicada e abordagem qualitativa, foi realizada com estudantes do 3º ano do Ensino Médio em uma escola pública de Pernambuco, integrando recursos digitais e uma abordagem interdisciplinar para estimular a consciência socioambiental e a pensamento crítico. A metodologia envolveu a aplicação de atividades interativas em uma plataforma online, com os dados sendo interpretados qualitativamente, a partir dos três eixos da FlexQuest: Questões, Processos e Transferência. Os resultados mostraram que a PetroFlex favoreceu o desenvolvimento de habilidades críticas, como argumentação, análise de problemas complexos e tomada de decisão, além de ampliar a compreensão dos impactos socioambientais e das responsabilidades políticas e econômicas relacionadas ao desastre. Conclui-se que a PetroFlex é potencialmente eficaz na promoção de uma aprendizagem interdisciplinar, alinhada às diretrizes da Base Nacional Comum Curricular e aos Objetivos de Desenvolvimento Sustentável da Organização das Nações Unidas, contribuindo para a formação crítica e cidadã dos estudantes."},{"ano":2025,"titulo":"Promoção da educação ecológica com estudantes do Ensino Fundamental via Unidade de Ensino Potencialmente Significativa","autores":"José Antônio Bezerra de Oliveira","autores_todos":["Lucas Roberto Santos de Carvalho","Kátia Aparecida da Silva Aquino","José Antônio Bezerra de Oliveira"],"estudantes":"Lucas Roberto Santos de Carvalho","periodico":"DEBATES EM EDUCAÇÃO","qualis":"A3","area":"Educação","temas":["Aprendizagem Significativa","Avaliação e Trajetórias","Educação Ambiental"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.28998/2175-6600.2025v17n39pe18225","doi":"10.28998/2175-6600.2025v17n39pe18225","resumo":"A promoção de uma educação ecológica crítica no Ensino Fundamental requer estratégias didáticas que superem a fragmentação do conhecimento e possibilitem a construção de posturas ambientalmente responsáveis desde a infância. Nesse contexto, destaca-se a potencialidade das Unidades de Ensino Potencialmente Significativas como caminhos para articular conhecimentos científicos à realidade dos estudantes. Este estudo teve como objetivo analisar os impactos decorrentes da implementação de uma Unidade de Ensino Potencialmente Significativa (UEPS), visando promover uma aprendizagem significativa e crítica de conceitos ecológicos por parte de estudantes do Ensino Fundamental. Com base na Teoria da Aprendizagem Significativa de Ausubel e na Perspectiva Crítica de Moreira, uma UEPS foi concebida e aplicada em estudantes do 6º ano do Ensino Fundamental, sendo constituída de ações pedagógicas como observações do ambiente, discussões e a resolução de problemas ecológicos contextualizados. Os resultados foram obtidos pela avaliação de questionários aplicados antes e após a intervenção, além das observações do professor regente. A análise dos dados evidenciou uma evolução significativa na assimilação, retenção e capacidade dos estudantes de aplicar os conceitos ecológicos aprendidos, demonstrando a eficácia da UEPS em favorecer tanto a construção do conhecimento ecológico quanto o desenvolvimento de uma consciência ambiental crítica e ativa."},{"ano":2025,"titulo":"UNIDADE DE ENSINO POTENCIALMENTE SIGNIFICATIVA PARA O ESTUDO REMOTO DOS HORMÔNIOS NA EDUCAÇÃO BÁSICA","autores":"José Antônio Bezerra de Oliveira","autores_todos":["José Antônio Bezerra de Oliveira","Lucas Roberto Santos de Carvalho","Kátia Aparecida da Silva Aquino"],"estudantes":"Lucas Roberto Santos de Carvalho","periodico":"REVISTA CIÊNCIAS & IDÉIAS","qualis":"A3","area":"Ensino (Ciências/Exatas)","temas":["Aprendizagem Significativa","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.22407/2176-1477/2025.v16.2681","doi":"10.22407/2176-1477/2025.v16.2681","resumo":"No contexto do ensino de Ciências na Educação Básica, a utilização de estratégias pedagógicas bem estruturadas pode criar condições que possibilitem a aprendizagem significativa dos alunos. Nesta direção, este estudo objetivou desenvolver e aplicar uma Unidade de Ensino Potencialmente Significativa de forma remota, no contexto do ensino de Ciências na Educação Básica, tendo como temática o estudo dos hormônios. Ao longo dos passos sequenciais da UEPS, que vão desde o Levantamento de Conhecimentos Prévios até a Reconciliação Integrativa, foram observados avanços significativos na aprendizagem dos alunos. A abordagem adotada ativou conhecimentos prévios, promoveu interação ativa com o conteúdo e estimulou o pensamento crítico dos alunos por meio da resolução de problemas contextualizados. A análise dos resultados demonstrou considerável articulação conceitual e uma compreensão mais profunda sobre o tema abordado, indicando uma progressão em direção à aprendizagem significativa. Esse estudo destaca não apenas a eficácia da UEPS em um ambiente remoto, mas também sua relevância no contexto desafiador da pandemia, oferecendo insights para o aprimoramento contínuo de estratégias de ensino."},{"ano":2025,"titulo":"Voices and Melodies of Artistic Precarity: The Unbearable Flexibility of Subjectivity in Chilean Independent Musicians","autores":"Gabriel Fortes","autores_todos":["Mauricio Toval-Gajardo","Álvaro Soto Roy","Fernanda Manríquez","Gabriel Fortes"],"estudantes":[],"periodico":"HUMAN ARENAS","qualis":"A3","area":"Psicologia","temas":"Psicologia e Subjetividade","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1007/s42087-025-00486-x","doi":"10.1007/s42087-025-00486-x","resumo":""},{"ano":2024,"titulo":"A Argumentação Dialógica como Fundamento para Aprendizagem Significativa Crítica na Construção Individual de Mapas Conceituais","autores":["Raquel Cordeiro Nogueira Lima","Sylvia De Chiaro"],"autores_todos":["Sylvia De Chiaro","Kátia Aparecida Da Silva Aquino","Raquel Cordeiro Nogueira Lima"],"estudantes":[],"periodico":"REVISTA DEBATES EM ENSINO DE QUÍMICA","qualis":"A1","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Aprendizagem Significativa","Metacognição e Autorregulação","Pensamento Crítico e Reflexivo","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.53003/redequim.v10i1.5534","doi":"10.53003/redequim.v10i1.5534","resumo":"Pensar a prática pedagógica a partir da preocupação e compromisso com uma aprendizagem significativa e crítica implica necessariamente em refletir sobre estratégias didáticas que envolvam um funcionamento crítico e reflexivo dos estudantes a respeito dos conteúdos conceituais trabalhados. Apoiando-se na dimensão dialógica da argumentação, esse estudo se propõe a mostrar que a construção de mapas conceituais, ainda que individualmente, pode se constituir em um excelente caminho nesse sentido. Essa proposta se fundamenta na ideia defendida aqui, e apoiada em estudos anteriores, da existência de uma dimensão inerentemente argumentativa caracterizando essa construção. Para tanto, dois estudantes do 2º ano do Ensino Médio foram videogravados durante toda a construção individual de um mapa conceitual sobre Sabonetes, no componente curricular Química. Foi solicitado que verbalizassem todos os movimentos realizados por eles no decorrer da atividade. As análises dessa construção denotaram um intenso funcionamento argumentativo, metacognitivo, crítico e reflexivo a partir dos diálogos entre as inúmeras vozes que se mostraram presentes. Esses diálogos de vozes refletiram uma constante negociação entre diferentes perspectivas a respeito da temática e consequente aprendizagem significativa e crítica por parte dos estudantes."},{"ano":2024,"titulo":"Argumentação, prova e demonstração na visão de estudantes ingressantes no curso de licenciatura em Matemática","autores":"João Carlos Caldato Correia","autores_todos":["João Carlos Caldato","Lilian Nasser"],"estudantes":[],"periodico":"EID","qualis":"A2","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Formação de Professores","Avaliação e Trajetórias","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.47369/eidea-23-3-3985","doi":"10.47369/eidea-23-3-3985","resumo":"O objetivo deste artigo é identificar como estudantes ingressantes no curso de licenciatura em Matemática interpretam as terminologias argumentação, prova e demonstração. Trata-se de um recorte da primeira etapa de uma pesquisa sobre argumentação no âmbito da Educação Matemática. Ao todo, 78 licenciandos de três instituições públicas de Ensino Superior participaram da produção de dados. Para a análise dos dados, foi utilizado um software que permite realizar análises estatísticas sobre dados textuais. Em vista disso, um objetivo secundário deste artigo é apresentar a possibilidade de utilizar o software IRaMuTeQ como um instrumento que auxilia na análise e na criação de categorias. Assim, foi possível inferir que o significado destas terminologias não é consensual entre os participantes e que, na visão deles, a prova estaria relacionada a algo mais formal ou a uma generalização, enquanto a demonstração estaria relacionada a algo mais informal ou a uma etapa que antecede a prova."},{"ano":2024,"titulo":"Employing the intellectual virtues to better understand argumentation interventions in education","autores":"Gabriel Fortes","autores_todos":["Gabriel Fortes","Leandro De Brasi","Michael Baumtrog"],"estudantes":[],"periodico":"FRONTLINE LEARNING RESEARCH","qualis":"Sem Qualis","area":"Educação","temas":"Argumentação","disciplina":[],"tipo":"Teórico","idioma":"Inglês","link":"https://doi.org/10.14786/flr.v12i2.1247","doi":"10.14786/flr.v12i2.1247","resumo":"Argumentation-based classroom interventions are a growing alternative for stimulating conceptual learning, thinking, and communicative skills. However, not all classroom argumentation is desired, nor does every argumentation design lead students to develop their abilities and understanding. In the educational literature, productive argumentation has been associated particularly with deliberation due to the design properties that deliberative practices demand from students, such as collaborating towards a goal, revising one’s own opinion, listening to others, and changing their minds when it is necessary to arrive at a collective decision or problem resolution. We contend that what makes deliberation productive is not argumentation in itself, but how a certain type of design scaffolds students into virtuous-like behavior, which can be the enabling condition for productive argumentation in classroom activities. Through the exploration of three cases of classroom argumentation and discussion experiences, we hypothesize that virtuous-like behavior may serve as an enabling condition for each intervention. In particular, intellectually humble behaviors could be scaffolded within these interventions because all three create the proper environment for students to revise their own positions, listen carefully to others, and change their minds in light of appropriate reasoning or new evidence. Employing an intellectual virtues framework, advances our understanding of how to design class"},{"ano":2024,"titulo":"Equidade e informação: o desafio do acesso à educação infantil nas capitais brasileiras","autores":"Gabriel Fortes","autores_todos":["Pedro Gomes","Marcel De Lima Correia","Gabriel Fortes","Angelina Nunes de Vasconcelos"],"estudantes":[],"periodico":"CADERNOS DE EDUCAÇÃO, TECNOLOGIA E SOCIEDADE","qualis":"A3","area":"Educação","temas":"Políticas e Equidade Educacional","disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.14571/brajets.v17.n4.1513-1533","doi":"10.14571/brajets.v17.n4.1513-1533","resumo":"O presente estudo investiga as desigualdades no acesso à educação infantil nas 27 capitais brasileiras, com foco nos processos de matrícula e pré-matrícula nas redes municipais de ensino. A pesquisa, de natureza documental, baseou-se na coleta de dados disponíveis nos sites das prefeituras e secretarias de educação, buscando analisar como os sistemas de distribuição de vagas abordam a justiça social e equidade educacional. Os resultados revelam lacunas significativas no acesso à informação. Em cerca de um terço das capitais, os dados sobre documentos necessários para a matrícula não estão disponíveis fora do período de matrículas, comprometendo o planejamento das famílias. Além disso, em 18 capitais, não foram divulgados os critérios para a alocação de vagas, o que indica falta de transparência. Também se observa que 12 capitais realizam o processo de pré-matrícula exclusivamente online, o que exclui famílias sem acesso à internet, prejudicando ainda mais a equidade no acesso à educação. As práticas analisadas indicam a necessidade de políticas educacionais mais inclusivas, que considerem as diversidades socioeconômicas da população. O estudo sugere a implementação de medidas como a criação de pontos de acesso à internet em locais públicos e o fortalecimento de canais de atendimento presenciais e virtuais para garantir maior suporte às famílias no processo de matrícula."},{"ano":2024,"titulo":"Exploring the Unexpected: the Relationship Between Higher Family Income and Dropout Risk","autores":"Gabriel Fortes","autores_todos":["Gabriel Fortes","Angelina Nunes","Julio Cezar Albuquerque","Gleidson Diego Lopes","Luan Filipy Freires","Leonardo Soares","Leogildo Alves","Thiago Cordeiro","Ibert Bittencourt Santana","Seiji Isotani"],"estudantes":[],"periodico":"PRAXIS & SABER","qualis":"A1","area":"Educação","temas":"Avaliação e Trajetórias","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.19053/uptc.22160159.v15.n41.2024.16848","doi":"10.19053/uptc.22160159.v15.n41.2024.16848","resumo":"This study investigates the paradoxical influence of family income on school dropout risks among Brazilian public-school students. Discussing previous results that challenges traditional perspectives on school dropout by examining how students from higher family income show higher dropout risk. We hypothesize that this is due to flexible capitalism changes in our societies labor market and to the devaluation of schools as a meaningful place for student’s life projects. Analyzing data from 15,924 Brazilian high school and middle school students using Multivariate Analysis of Variance (MANOVA) and univariate models, the study reveals that students from higher-income families are more likely to drop out when they perceive school as less relevant for their future careers. This unexpected finding suggests that, unlike most literature on this field, higher income students might be at greater risk of dropout due to the pressure to enter the workforce and the perceived lack of school's alignment with their career aspirations. This study contributes to the understanding of school dropout in the global south, proposing the need for educational reforms that align with contemporary labor market realities."},{"ano":2024,"titulo":"FLEX-AS: ESTRATÉGIA DIDÁTICA PARA O ENSINO DE CIÊNCIAS NAS PERSPECTIVAS DA aPRENDIZAGEM SIGNIFICATIVA E FLEXIBILIDADE COGNITIVA","autores":"José Antônio Bezerra de Oliveira","autores_todos":["José Antônio Bezerra de Oliveira","Patrícia Smith Cavalcante","Kátia Aparecida da Silva Aquino"],"estudantes":[],"periodico":"INVESTIGAÇÕES EM ENSINO DE CIÊNCIAS (ONLINE)","qualis":"A1","area":"Ensino (Ciências/Exatas)","temas":["Aprendizagem Significativa","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.22600/1518-8795.ienci2024v29n3p389","doi":"10.22600/1518-8795.ienci2024v29n3p389","resumo":"This study is a segment of a broader research project aimed at identifying connections between the Theory of Meaningful Learning (TML), its critical perspective (CML), and the Theory of Cognitive Flexibility (TCF). Based on this dialogue, the study sought to design a didactic strategy for science teaching in basic education to facilitate the promotion of meaningful and critical learning. Analyzing the principles of these theories led to the identification of five points of convergence, or descriptors, namely: Emphasis on Knowledge Construction, Relevance of Prior Knowledge, Focus on Deep Understanding, Contextualized Learning, and Learning Progressivity. These descriptors guided the development of a didactic strategy for science teaching. The strategy, titled FLEX-AS, consists of four stages: Planning, Preparation, Experience, and Evaluation. Each stage is detailed and theoretically and methodologically grounded. Reflections on the creation of FLEX-AS demonstrated the conceptual coherence of integrating the underlying theories into a less theoretical and more practical framework for educators."},{"ano":2024,"titulo":"Modelagem matemática do jogo de cartas Yu-Gi-Oh! para o ensino de inequações polinomiais do 1º grau","autores":"João Carlos Caldato Correia","autores_todos":["Lucas da Silva Barreto","João Carlos Caldato","Leandro de Oliveira Pereira"],"estudantes":[],"periodico":"STUDIES IN EDUCATION SCIENCES","qualis":"C","area":"Ensino (Ciências/Exatas)","temas":["Aprendizagem Significativa","Metodologias Ativas e Tecnologia","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.54019/sesv5n2-007","doi":"10.54019/sesv5n2-007","resumo":"O objetivo deste artigo é apresentar uma proposta de sequência didática, em que é explorada uma aplicação da modelagem matemática no contexto do jogo de cartas Yu-Gi-Oh, para o ensino de inequações polinomiais de 1º grau. Nesta sequência didática trazemos uma Modelagem Matemática associada ao uso de jogos educacionais, sala de aula invertida e aprendizagem em grupo com o propósito de proporcionar um ambiente de aprendizado que promova a compreensão crítica e prática da Matemática, preparando os alunos para enfrentar problemas do mundo real. A sequência proposta incorpora estratégias pedagógicas inovadoras, incluindo a aprendizagem em grupo, que promove a colaboração entre os alunos, a sala de aula invertida, na qual os alunos adquirem conhecimento prévio antes das aulas para aproveitar ao máximo o tempo em sala, e a gamificação, que transforma o processo de aprendizagem em uma experiência envolvente e lúdica. A abordagem proposta visa não apenas promover o entendimento das inequações polinomiais de 1º grau, mas também desenvolver habilidades críticas e de resolução de problemas nos alunos. Além disso, buscamos fornecer insights sobre as potencialidades do uso de jogos no ensino de Matemática, explorando suas aplicações em sala de aula e o possível impacto no engajamento e na aprendizagem significativa dos alunos. Ao tornar o processo de aprendizagem mais agradável e significativo para os alunos, a combinação de Modelagem Matemática, gamificação, sala de aula invertida e apren"},{"ano":2024,"titulo":"Percepções Docentes em Relação ao Agir e Fazer Profissional no Contexto Pandêmico Vivido","autores":"Jose Ayron Lira dos Anjos","autores_todos":["Gleyds Domingues","Kátia Cunha","José Ayron Lira dos Anjos"],"estudantes":[],"periodico":"REVISTA FAEEBA","qualis":"A1","area":"Educação","temas":"Formação de Professores","disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.21879/faeeba2358-0194.2024.v33.n74.p133-150","doi":"10.21879/faeeba2358-0194.2024.v33.n74.p133-150","resumo":"A discussão teórico-metodológica construída no artigo tem como proposta analisar as percepções docentes que foram constituídas no contexto pandêmico, ocorrido entre os anos de 2020-2021, como resposta ao cenário educacional configurado, a qual demandou ajustes e acomodações ao agir profissional, marcado pelo caráter emergencial que produziu incertezas, mas ao mesmo tempo resiliência e superação. Diante deste cenário, foi eleita como questão problematizadora a seguinte pergunta: de que maneira o contexto pandêmico atingiu o fazer e agir profissional dos docentes, no que diz respeito à prática educativa concretizada no processo ensino e aprendizagem em sua estrutura e organização? Para que se compreenda este momento, fez-se uso da análise do discurso, a fim de identificar nos depoimentos dos docentes o dito, não dito e os silêncios. Busca-se com a investigação analisar não apenas os impactos da pandemia no âmbito da prática docente, mas o posicionamento assumido diante do seu contexto de trabalho. Ao final da análise, observa-se que os docentes se reinventam e buscam encontrar alternativas que sejam relacionais, coerentes e integradoras com o objetivo educativo almejado."},{"ano":2024,"titulo":"Psychological Well-Being Among Adolescents: The Role of Parenting Styles, Causal Attributions of Academic Success/Failure, and Perceived School Performance","autores":"Gabriel Fortes","autores_todos":["Alane Pereira Madalena","Gleidson Diego Lopes Loureto","José Anderson Galdino Santos","Layrtthon Carlos de Oliveira Santos","Gabriel Fortes","Leogildo Alves Freires"],"estudantes":[],"periodico":"JOURNAL OF PSYCHOEDUCATIONAL ASSESSMENT","qualis":"A3","area":"Psicologia","temas":"Psicologia e Subjetividade","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1177/07342829241245462","doi":"10.1177/07342829241245462","resumo":"We investigated the effects of perceived parenting styles, causal attributions for academic success/failure, and perceived school performance (PSP) on adolescents’ psychological well-being (PWB). Participants were 200 Brazilian adolescents who answered the Parenting Styles &amp; Dimensions Questionnaire, the Psychological Well-Being Scale, and the Rating Scale of Causal Attributions for Academic Success/Failure (RSCA). The results showed that adolescents’ PWB was predicted by authoritative parenting style (APS), internal and controllable attributions (appropriate motivations to cope with academic success/failure; ICASF), and PSP. In addition, we tested a mediation model showing that the ICASF mediated the relationship between APS and PSP, which in turn led to better PWB. These results highlighted the relevance of parenting styles and school-based causal attributions for the understanding of adolescents’ mental health. Our findings can support interventions that enable more effective teaching–learning processes, which are associated with higher levels of mental health for the adolescent population."},{"ano":2024,"titulo":"What Learning Strategies are Used by Programming Students? A Qualitative Study Grounded on the Self-regulation of Learning Theory","autores":"Gabriel Fortes","autores_todos":["Leonardo Silva","António Mendes","Anabela Gomes","Gabriel Fortes"],"estudantes":[],"periodico":"ACM TRANSACTIONS ON COMPUTING EDUCATION","qualis":"A1","area":"Ensino (Ciências/Exatas)","temas":["Metacognição e Autorregulação","Ensino de Ciências e Matemática"],"disciplina":"Computação","tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1145/3635720","doi":"10.1145/3635720","resumo":"Self-regulation of learning (SRL) is an essential ability for academic success in multiple educational contexts, including programming education. However, understanding how students regulate themselves during programming learning is still limited. This exploratory research aimed to investigate the regulatory strategies externalized by 51 students enrolled in an introductory programming course. The objective was to identify the SRL strategies used by these students during multiple phases of the learning process and compare the SRL behavior of high and low-performers. The following research questions guided this investigation: (RQ1) What regulation of learning strategies are used by programming students?; and (RQ2) How do the SRL strategies used by high and low-performing students differ?. The findings demonstrate that learning to program involves complex psychological resources (e.g., cognition, metacognition, behavior, motivation, and emotion) and that students present heterogeneity in their SRL repertoire. In addition, high and low-performing students showed significant differences in how they regulate, which can contribute to understanding the factors that may contribute to learning programming. Lastly, we argue that for analyzing SRL strategies, it is necessary to consider the specificities of programming education, which motivated the development of a conceptual framework to describe the identified strategies and regulatory phases in this learning domain."},{"ano":2023,"titulo":"A UTILIZAÇÃO DE UM PROJETO DE ENSINO NA CONSTRUÇÃO DO ENTENDIMENTO TEÓRICO E PRÁTICO ACERCA DA TERMODINÂMICA","autores":"Jose Ayron Lira dos Anjos","autores_todos":[],"estudantes":[],"periodico":"EXPERIÊNCIAS EM ENSINO DE CIÊNCIAS (UFRGS)","qualis":"A3","area":"Ensino (Ciências/Exatas)","temas":"Ensino de Ciências e Matemática","disciplina":"Química","tipo":"Teórico","idioma":"Não informado","link":"https://fisica.ufmt.br/eenciojs/index.php/eenci/article/view/1206/1010","doi":"","resumo":""},{"ano":2023,"titulo":"ARGUMENTAÇÃO E APRENDIZAGEM BASEADA EM PROBLEMAS: PROCESSO DE CONSTRUÇÃO DE CONHECIMENTO CRÍTICO E REFLEXIVO EM SALA DE AULA DE FÍSICA","autores":"Sylvia De Chiaro","autores_todos":["Jeyvson Correia de Almeida","Sylvia De Chiaro"],"estudantes":[],"periodico":"INVESTIGAÇÕES EM ENSINO DE CIÊNCIAS (ONLINE)","qualis":"A1","area":"Educação","temas":["Argumentação","Metacognição e Autorregulação","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.22600/1518-8795.ienci2023v28n2p462","doi":"10.22600/1518-8795.ienci2023v28n2p462","resumo":"O presente trabalho tem por objetivo analisar o impacto que a interface entre a Aprendizagem Baseada em Problemas (ABP) e a argumentação pode desempenhar para a promoção da construção do conhecimento no componente curricular de Física, em uma sala de aula regular do Ensino Médio. Tomamos como foco de análise as interações dialógicas entre aluno-aluno e aluno-tutor ao longo da resolução de um problema na metodologia ABP, por entendermos que a configuração deste tipo de metodologia favorece o debate crítico e reflexivo de ideias, característico de um funcionamento metacognitivo. Os resultados apontam indícios de que a metodologia ABP é propícia ao desenvolvimento de ações discursivas que garantem a argumentação, desde que o tutor tenha conhecimento das mesmas e as utilize intencionalmente para manejar as discussões. Além disso, foi compreendido que os movimentos discursivos característicos da argumentação denotam um interessante potencial para o desenvolvimento da função metacognitiva autorreguladora de monitoramento do pensamento em um processo de ensino e de aprendizagem na Física, favorecendo, pois, o exercício do pensamento crítico e reflexivo."},{"ano":2023,"titulo":"AULAS REMOTAS NA PÓS-GRADUAÇÃO: ANÁLISE E PERCEPÇÕES SOBRE O USO DE METODOLOGIAS ATIVAS EM COMPONENTE CURRICULAR OFERTADO DURANTE A PANDEMIA DA COVID-19","autores":"José Antônio Bezerra de Oliveira","autores_todos":["José Antônio Bezerra de Oliveira","Alba Flora Pereira","Marcelo Lins Muniz de Melo Santos","Paula Basto Levay Lage","Patrícia Smith Cavalcante"],"estudantes":[],"periodico":"ENSINO DE CIÊNCIAS E TECNOLOGIA EM REVISTA","qualis":"A4","area":"Educação","temas":"Metodologias Ativas e Tecnologia","disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.31512/encitec.v13i2.1023","doi":"10.31512/encitec.v13i2.1023","resumo":"O presente estudo visou refletir sobre um percurso didático, desenvolvido a partir do uso de metodologias ativas, realizado em um componente curricular de pós-graduação no cenário da educação digital diante da situação pandêmica da Covid-19 iniciada em 2020. As abordagens didáticas aconteceram de modo remoto e as docentes responsáveis pelo referido componente curricular submeteram os discentes a experienciarem variadas formas de ensinar-aprender. As estratégias utilizadas geraram, nos discentes, criticidade, reflexões e tomada de decisões nos estudos sobre os tipos de métodos de pesquisa em educação, tema central do componente. Nesta direção, verifica-se que as interações docente-discente e discente-discente ocasionadas pelas atividades propostas pareceram ter contribuído de forma positiva para a formação dos discentes, indicando que o ensino remoto, com articulação e planejamento docente adequados e mediados por tecnologias e metodologias ativas, pode promover aprendizagens mais significativas."},{"ano":2023,"titulo":"Advancing school dropout early warning systems: the IAFREE relational model for identifying at-risk students","autores":"Gabriel Fortes","autores_todos":["Angelina Nunes de Vasconcelos","Leogildo Alves Freires","Gleidson Diego Lopes Loureto","Gabriel Fortes","Júlio Cezar Albuquerque da Costa","Luan Filipy Freire Torres","Ig Ibert Bittencourt","Thiago Damasceno Cordeiro","Seiji Isotani"],"estudantes":[],"periodico":"FRONTIERS IN PSYCHOLOGY","qualis":"A2","area":"Educação","temas":"Avaliação e Trajetórias","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.3389/fpsyg.2023.1189283","doi":"10.3389/fpsyg.2023.1189283","resumo":"Introduction: There is a global effort to address the school dropout phenomenon. The urgency to act on it comes from the harmful evidence that school dropout has on societal and individual levels. Early Warning Systems (EWS) for school dropout at-risk student identification have been developed to anticipate and help schools have a better chance of acting on it. However, several studies point to a doubt that Correct EWS may come too late because they use only publicly available and general student and school information. We hypothesize that having a tool to assess more subjective and inter-relational factors would help anticipate where and when to act to prevent school dropout. This study aimed to develop a multidimensional measure for assessing relational factors for predicting school dropout (SD) risk in the Brazilian context. Methods: We performed several procedures, including (a) the specialized literature review, (b) the item development of the Relational Factors for the Risk of School Dropout Scale (IAFREE in Portuguese), (c) the content validity analysis, (d) a pilot study, and (e) the administration of the IAFREE to a large Brazilian sample of high school and middle school students (N = 15,924). Results: After the theoretical steps, we found content validity for five relational dimensions for SD (Student-School, Student-School Professionals, Student-Family, Student-Community, and Student-Student) that include 12 facets of risk factors. At the empirical stage, confirmat"},{"ano":2023,"titulo":"Análise da (Re)construção de Mapas Conceituais como estratégia na resolução de problemas de Química","autores":"Jose Ayron Lira dos Anjos","autores_todos":["Renan Lima","José Ayron Lira dos Anjos"],"estudantes":[],"periodico":"INSTRUMENTO - REVISTA EM ESTUDO E PESQUISA EM EDUCAÇÃO","qualis":"A3","area":"Ensino (Ciências/Exatas)","temas":["Aprendizagem Significativa","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.34019/1984-5499.2023.v25.38602","doi":"10.34019/1984-5499.2023.v25.38602","resumo":"Este trabalho é um recorte de uma pesquisa de mestrado que discorre sobre algumas dificuldades no ensino e aprendizagem, em especial nos conteúdos de Química, atentando-se para algumas estratégias que poderiam promover melhorias no contexto citado. Com base nisso, buscamos analisar como a elaboração de mapas conceituais, como estratégia para a resolução de uma situação-problema, poderia favorecer uma aprendizagem significativa de conteúdos de Química. Metodologicamente, os mapas conceituais com vista à resolução da situação-problema foram analisados com base em uma abordagem qualitativa. Os resultados obtidos indicaram que os mapas conceituais se constituem como uma ferramenta que fornece possibilidades de organização e construção de estratégias que podem ser aplicadas na resolução de problemas, favorecendo a aprendizagem de conteúdos de química de maneira significativa."},{"ano":2023,"titulo":"Fostering regulatory processes using computational scaffolding","autores":"Gabriel Fortes","autores_todos":["Leonardo Silva","António Mendes","Anabela Gomes","Gabriel Fortes"],"estudantes":[],"periodico":"INTERNATIONAL JOURNAL OF COMPUTER-SUPPORTED COLLABORATIVE LEARNING","qualis":"Sem Qualis","area":"Ensino (Ciências/Exatas)","temas":["Metacognição e Autorregulação","Metodologias Ativas e Tecnologia","Ensino de Ciências e Matemática"],"disciplina":"Computação","tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1007/s11412-023-09388-y","doi":"10.1007/s11412-023-09388-y","resumo":"Abstract The use of computational scaffolding is a crucial strategy to foster students’ regulation of learning skills, which is associated with increased learning achievement. However, most interventions treat the regulatory processes as individual actions isolated from a social context. This view contradicts the most recent research that points to the importance of studying the regulatory phenomenon from a social-cognitive perspective, where students’ interactions influence their regulation of the learning process. This work explores these problems and presents multiple scaffolds to promote Self-regulation of Learning (SRL), co-regulation, and socially shared regulation of learning (SSRL) embedded within a computer-supported collaborative learning environment. A single-blind randomized controlled trial was performed with students ( n = 71) enrolled in an online introductory programming course. Students were randomly assigned to three groups: 1) SRL-only support, 2) SRL, co-regulation, and SSRL support, and 3) a no support control group. The findings revealed that students who received regulatory support achieved higher course grades than the control group. However, only students who received SSRL and co-regulation support achieved superior performance in collaborative activities, confirming the importance of this type of regulation. Even though students did not increase in SRL aptitude, the intervention provided support for achieving higher grades in the course."},{"ano":2023,"titulo":"Impactos do componente curricular `Argumentação na Educação? na competência argumentativa e no manejo de metodologias potencialmente argumentativas por futuros professores","autores":["Raquel Cordeiro Nogueira Lima","Sylvia De Chiaro"],"autores_todos":["Raquel Cordeiro Nogueira Lima","Selma Leitão","Sylvia De Chiaro"],"estudantes":[],"periodico":"LINHA D'AGUA","qualis":"Sem Qualis","area":"Educação","temas":["Argumentação","Pensamento Crítico e Reflexivo","Desenvolvimento e Linguagem","Políticas e Equidade Educacional"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.11606/issn.2236-4242.v36i3p26-50","doi":"10.11606/issn.2236-4242.v36i3p26-50","resumo":"O presente trabalho investigou os impactos da participação de estudantes de Pedagogia no componente curricular eletivo ‘Argumentação na Educação’, que propõe desenvolver nos estudantes competências necessárias para argumentar, bem como para construir e mediar estratégias didáticas argumentativas em ambientes educacionais. Observando os estudantes durante um semestre letivo, nossos objetivos envolveram investigar os impactos na competência argumentativa, bem como na apropriação de conhecimentos de conteúdo pedagógico, relacionados ao manejo da argumentação. As análises apontaram melhorias na qualidade da argumentação construída, além de refinamento do pensamento reflexivo. Houve também ganhos nas habilidades de planejamento e de desenho de atividades potencialmente argumentativas, no emprego de diversas ações discursivas durante a mediação da atividade prática docente, bem como um grau de apropriação dos princípios do Ensino Dialógico. Tais resultados indicam que a combinação dos elementos presentes na disciplina (currículo, metodologias, cultura, postura do professor) foi essencial para o desenvolvimento observado."},{"ano":2023,"titulo":"LINGUAGEM E DESENVOLVIMENTO EM CONTEXTO DE CRISE: EXPLORANDO OS EFEITOS DO ISOLAMENTO SOCIAL NA EDUCAÇÃO","autores":"Gabriel Fortes","autores_todos":[],"estudantes":[],"periodico":"ORGANON","qualis":"A3","area":"Educação","temas":"Desenvolvimento e Linguagem","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://seer.ufrgs.br/index.php/organon/article/view/135045","doi":"","resumo":""},{"ano":2023,"titulo":"MAPAS CONCEITUAIS NA AVALIAÇÃO DA APRENDIZAGEM DECORRENTE DE SEQUÊNCIAS DE ENSINO POTENCIALMENTE SIGNIFICATIVAS PARA O ENSINO DE CIÊNCIAS","autores":"José Antônio Bezerra de Oliveira","autores_todos":["José Antônio Bezerra de Oliveira","Patrícia Smith Cavalcante","Kátia Aparecida da Silva Aquino"],"estudantes":[],"periodico":"ENSINO DE CIÊNCIAS E TECNOLOGIA EM REVISTA","qualis":"A4","area":"Ensino (Ciências/Exatas)","temas":["Aprendizagem Significativa","Avaliação e Trajetórias","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.31512/encitec.v13i1.1068","doi":"10.31512/encitec.v13i1.1068","resumo":"O presente artigo versa sobre a avaliação de sequências de ensino idealizadas para o ensino de ciências que tenham potencial para desenvolver aprendizagens significativas, ou seja, que levem em consideração os conhecimentos prévios do estudante e a assimilação de novos conceitos de modo articulado, não-literal e substantivo, propiciando o surgimento de novos significados para ele. O objetivo do estudo foi avaliar a aprendizagem decorrente de sequências de ensino potencialmente significativas para o ensino de ciências via mapas conceituais. Sendo assim, os estudantes foram submetidos a algumas sequências de ensino e produziram mapas de conceitos antes e após cada abordagem da sequência. A análise comparativa dos mapas conceituais para cada abordagem constatou potencialidade das sequências de ensino aplicadas para a promoção de uma aprendizagem significativa. Além disso, percebeu-se que os mapas favoreceram a organização conceitual dos estudantes, indicando que seu uso nas aulas de ciências pode auxiliar o professor nos processos de ensino e aprendizagem de forma significativa e subsidiar novas perspectivas de avaliação do aprendizado."},{"ano":2023,"titulo":"METODOLOGIA EM CINCO PASSOS: Metodologia Ativa no ensino de Magnetismo","autores":"Kátia Calligaris Rodrigues","autores_todos":[],"estudantes":[],"periodico":"EXPERIÊNCIAS EM ENSINO DE CIÊNCIAS (UFRGS)","qualis":"A3","area":"Ensino (Ciências/Exatas)","temas":["Metodologias Ativas e Tecnologia","Ensino de Ciências e Matemática"],"disciplina":"Física","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://fisica.ufmt.br/eenciojs/index.php/eenci/article/view/1103","doi":"","resumo":""},{"ano":2023,"titulo":"REDE SOCIAL INSTAGRAM E A TEORIA COGNITIVA DA APRENDIZAGEM MULTIMÍDIA: ANÁLISE DE IMAGENS COM CONTEÚDOS QUÍMICOS DE PERFIL EDUCACIONAL","autores":"Tais de Oliveira Silva","autores_todos":["Yrailma Katharine de Sousa","Karla Jeane Vilela De Oliveira","Tais de Oliveira Silva","Ricardo Ferreira das Neves"],"estudantes":[],"periodico":"INVESTIGAÇÕES EM ENSINO DE CIÊNCIAS (ONLINE)","qualis":"A1","area":"Ensino (Ciências/Exatas)","temas":["Metodologias Ativas e Tecnologia","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.22600/1518-8795.ienci2023v28n2p292","doi":"10.22600/1518-8795.ienci2023v28n2p292","resumo":"As imagens, em suas diversas formas de representação, atuam como promotoras de significados sociais, políticos e educacionais. No âmbito escolar, são amplamente utilizadas na abordagem de conteúdos, visando colaborar na compreensão de conceitos ao estudante. Todavia, em muitos casos, isso tem implicado em vicissitudes na forma como elas são apresentadas em sala de aula. O docente quando do uso de ilustrações presentes em livros, tecnologias e multimídias necessitam de critérios que possam ajudá-los a melhorar o desenvolvimento de sua prática, propiciando a disseminação adequada do conhecimento. Este estudo qualitativo-descritivo, objetivou analisar os princípios multimidiáticos no ensino-aprendizagem em Química, em imagens postadas em um perfil educacional do Instagram. Para isso, foi selecionado um perfil que abordava e discutia sobre conteúdos químicos, a partir de imagens estáticas sobre ligações químicas. As ilustrações foram classificadas e posteriormente analisadas, tendo como base os Princípios de Coerência, Contiguidade Espacial e Sinalização, relacionados à Carga de Redução de Processamento Estranho, da Teoria Cognitiva da Aprendizagem Multimídia. A Contiguidade Espacial se apresentou satisfatória, seguindo a relação de proximidade entre texto e imagem. Já o Princípio da Sinalização e da Coerência precisam ser mais delineados, no tocante à presença de elementos que podem provocar compreensões equivocadas/inapropriadas sobre os conceitos químicos. As postagens em Rede"},{"ano":2023,"titulo":"The Natural Tendency for Wide and Careful Listening: Exploring the Relationship Between Open-Mindedness and Psychological Science","autores":"Gabriel Fortes","autores_todos":["Gabriel Fortes","Leandro De Brasi"],"estudantes":[],"periodico":"INTEGRATIVE PSYCHOLOGICAL AND BEHAVIORAL SCIENCE","qualis":"A3","area":"Educação","temas":"Pensamento Crítico e Reflexivo","disciplina":[],"tipo":"Teórico","idioma":"Inglês","link":"https://doi.org/10.1007/s12124-023-09774-z","doi":"10.1007/s12124-023-09774-z","resumo":""},{"ano":2023,"titulo":"funcionamento metacognitivo docente na adequação de estratégias pedagógicas do modelo presencial para o remoto","autores":["Kátia Calligaris Rodrigues","Sylvia De Chiaro","Valter Cesar Montanher"],"autores_todos":["Sylvia De Chiaro","Kátia Calligaris Rodrigues","Valter César Montanher","Paula Eduarda Nunes Da Silva"],"estudantes":"Paula Eduarda Nunes da Silva","periodico":"REVISTA ESPAÇO PEDAGÓGICO","qualis":"A3","area":"Educação","temas":["Argumentação","Metacognição e Autorregulação","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.5335/rep.v30i0.14823","doi":"10.5335/rep.v30i0.14823","resumo":"Em função da pandemia da COVID19, o ensino remoto exigiu dos educadores grande capacidade de desenho pedagógico, isto é, capacidade de adaptar estratégias pedagógicas já existentes para novos contextos de ensino-aprendizagem. O processo de adaptação de uma disciplina de Argumentação na Educação, do formato presencial para o remoto, envolveu o exercício dessa capacidade de design de uma professora e suas monitoras. O desafio enfrentado nessa transposição era manter, no formato remoto, a potencialidade argumentativa das estratégias realizadas presencialmente, o que parece exigir um funcionamento metacognitivo contínuo. Diálogos desse grupo foram analisados e a presença de movimentos de monitoramento do pensamento mantenedor, elaborador e reconstrutor, foram uma constante. É possível, pois, admitirmos que a necessidade de adequação das estratégias pedagógicas, do formato presencial para o remoto, exigido por um momento de crise sanitária, propiciou um ambiente autorreflexivo propício tanto ao desenvolvimento metacognitivo como da capacidade de desenho pedagógico argumentativo das educadoras."},{"ano":2022,"titulo":"A argumentação e o desenvolvimento do pensamento crítico na construção de caminhos para mitigação de problemas ambientais da cidade de Bonito-PE","autores":"Jose Ayron Lira dos Anjos","autores_todos":["Djalma Alves de Oliveira","José Ayron Lira dos Anjos","Ana Paula Freitas da Silva"],"estudantes":"Paula Eduarda Nunes da Silva","periodico":"REVISTA DE ENSINO DE CIÊNCIAS E MATEMÁTICA (RENCIMA)","qualis":"A1","area":"Educação","temas":["Argumentação","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.26843/rencima.v13n4a21","doi":"10.26843/rencima.v13n4a21","resumo":"Problemas socioambientais é uma temática emergente que necessita ser debatida em sala de aula. Em uma cidade turística, onde os problemas ambientais são pouco discutidos, propomos trazer uma análise do processo de argumentação, voltada ao desenvolvimento do pensamento crítico dos estudantes, instigados pela discussão dos problemas ambientais percebidos por estes em sua cidade. Nesse contexto, realizou-se análise das argumentações expostas pelos discentes durante a apresentação das propostas de solução para os problemas socioambientais trabalhados. A metodologia utilizada foi da Aprendizagem Baseada em Problemas para instigar a emergência do processo argumentativo, de forma que os discentes apresentassem seu ponto de vista e propostas de solução para os problemas identificados. Percebemos em decorrência do processo, a remodelação das ideias, decorrente da organização de argumentos fundamentados cientificamente e construídos colaborativamente entre os estudantes, o que nos remete a indícios do desenvolvimento do pensamento crítico."},{"ano":2022,"titulo":"Avaliação da aprendizagem por parâmetros ausubelianos após vivência em uma unidade de ensino potencialmente significativa","autores":"José Antônio Bezerra de Oliveira","autores_todos":["Kátia Aparecida da Silva Aquino","Saulo De Tárcio Gomes do Nascimento","José Antônio Bezerra de Oliveira"],"estudantes":[],"periodico":"REVISTA ESPAÇO PEDAGÓGICO","qualis":"A3","area":"Educação","temas":["Aprendizagem Significativa","Avaliação e Trajetórias"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.5335/rep.v29i2.13114","doi":"10.5335/rep.v29i2.13114","resumo":"Percursos didáticos que se amparem em perspectivas construtivistas de aprendizagem são caminhos aspirados desde o final do século XX pelos estudiosos em educação. Outrossim, o processo avaliativo é um movimento complexo que demanda do professor certo esforço na busca por evidências da consolidação da aprendizagem. Posto isto, na perspectiva de uma aprendizagem significativa, este estudo apresenta uma proposta de Unidade de Ensino Potencialmente Significativa (UEPS) para a educação básica, além de uma sugestão para avaliar, por meio de parâmetros ausubelianos práticos, uma possível aprendizagem significativa que possa se desenvolver a partir da aplicação da Unidade. Para a avaliação do aprendizado com significado de forma mais assertiva, sugere-se a análise de critérios e itens que abarquem os domínios cognitivo, atitudinal, ciente, consciente e contextual da aprendizagem, utilizando múltiplos instrumentos avaliativos. Desta forma, as propostas aqui discutidas constituem-se como um recurso para subsidiar a análise e entendimento acerca dos episódios de aprendizagem significativa."},{"ano":2022,"titulo":"Como estudantes de Licenciatura em Matemática justificam problemas geométricos a partir de provas visuais?","autores":"João Carlos Caldato Correia","autores_todos":["João Carlos Caldato","Costa, André Pereira da","Lílian Nasser"],"estudantes":[],"periodico":"REVISTA BRASILEIRA DE ENSINO DE CIÊNCIA E TECNOLOGIA","qualis":"A2","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Formação de Professores","Metodologia de Pesquisa","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.3895/rbect.v15n3.15688","doi":"10.3895/rbect.v15n3.15688","resumo":"O objetivo deste artigo é investigar como estudantes de Licenciatura em Matemática justificam problemas geométricos a partir de provas visuais. Apesar do aumento no número de trabalhos de pesquisa em argumentação e provas no ensino de Matemática, observa-se que atividades desta natureza não são comuns na Educação Básica. Em outras palavras, grande parte dos professores que ensina Matemática não costuma pedir que seus alunos justifiquem as resoluções de tarefas ou os raciocínios utilizados. Em particular, não exploram atividades que desenvolvam a visualização na resolução de problemas ou justificativas para afirmativas de propriedades matemáticas. A visualização constitui um componente importante na compreensão de um conceito ou de um problema geométrico, e pode contribuir para esse desenvolvimento. Visualizar um problema significa compreendê-lo em termos de uma imagem visual (mental), constituindo uma parte essencial do método de solução. O percurso metodológico utilizado nesta pesquisa qualitativa foi o envio de um questionário online, elaborado no Google Forms, com três problemas caracterizados por provas visuais para licenciandos de Matemática de diversas Instituições de Ensino Superior. Por meio deste procedimento de coleta, a amostra por conveniência abrangeu 58 estudantes e as respostas foram analisadas de acordo com uma análise textual. Os dados indicam que, ao mobilizarem a visualização, embora os licenciandos consigam apresentar um encadeamento lógico em uma argument"},{"ano":2022,"titulo":"Descripción del conocimiento pedagógico del contenido de la argumentación en docentes que enseñan ciencias naturales en educación pública en Chile","autores":"Gabriel Fortes","autores_todos":["Antonia Larrain","Marisol Gómez","Maribel Calderón","Gabriel Fortes de Macedo","Francisca Ramírez","Valentina Guzmán","Hernán Cofré"],"estudantes":[],"periodico":"REVISTA EUREKA SOBRE ENSEÑANZA Y DIVULGACIÓN DE LAS CIENCIAS","qualis":"A1","area":"Educação","temas":"Argumentação","disciplina":[],"tipo":"Empírico/Prático","idioma":"Espanhol","link":"https://doi.org/10.25267/rev_eureka_ensen_divulg_cienc.2022.v19.i1.1602","doi":"10.25267/rev_eureka_ensen_divulg_cienc.2022.v19.i1.1602","resumo":"Science teaching has been called to contribute to citizenship insofar as it requires scientific competencies such as articulating theory and evidence, and the critical evaluation of different points of view. To promote argumentation in science teaching is key but not simple and requires teachers' pedagogical content knowledge (PCK) of argumentation. International literature has reported low PCK of argumentation in science teachers, but we scarcely know about this in Spanish speaking countries. is paper reports a study aimed at describing the PCK of argumentation on 10 primary science teachers in Chile. Lessons were video recorded, and interviews were conducted. Results show low PCK of argumentation overall, and declarative PCK does not necessarily relates with procedimental PCK. Moreover, different configurations of the dimensions of PCK of argumentation were observed, suggesting that there is not one possible learning progression, but different ones. Educational and scientific implications are discussed."},{"ano":2022,"titulo":"Formação crítico-reflexiva nos estágios em psicologia no Brasil: uma revisão de literatura narrativa","autores":["Gabriel Fortes","Nádia Oliveira da Silva"],"autores_todos":["Nádia Oliveira Da Silva","Gabriel Fortes Cavalcanti De Macedo"],"estudantes":[],"periodico":"REVISTA SUL AMERICANA DE PSICOLOGIA","qualis":"B2","area":"Psicologia","temas":["Formação de Professores","Pensamento Crítico e Reflexivo","Psicologia e Subjetividade","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.29344/2318650x.1.3104","doi":"10.29344/2318650x.1.3104","resumo":"Através de uma revisão de literatura narrativa, esse artigo investiga se as práticas didático-pedagógicas utilizadas na formação dos estágios específicos em psicologia fomentam a habilidade crítico-reflexiva, conforme as recomendações das diretrizes curriculares do curso. Foi utilizada a base de dados Scielo e os descritores: “formação profissional em psicologia”, “supervisão de estágio em psicologia” e “estágio supervisionado em psicologia”. Analisou-se dezoito artigos após a utilização dos critérios de inclusão e exclusão adotados. Todo o corpus consiste em estudos qualitativos de natureza descritiva. Não foi identificado o impacto que esses recursos apresentam no desenvolvimento de competências profissionais, sendo necessários estudos empíricos nesse campo."},{"ano":2022,"titulo":"INTERPRETANDO E AVALIANDO ARGUMENTAÇÕES: UMA ANÁLISE COM LICENCIANDOS INGRESSANTES DE MATEMÁTICA","autores":"João Carlos Caldato Correia","autores_todos":["João Carlos Caldato","Lilian Nasser"],"estudantes":[],"periodico":"VIDYA (SANTA MARIA. ONLINE)","qualis":"A2","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Formação de Professores","Desenvolvimento e Linguagem","Avaliação e Trajetórias","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.37781/vidya.v42i2.4208","doi":"10.37781/vidya.v42i2.4208","resumo":"Este artigo apresenta a primeira parte de uma pesquisa ampla, cuja segunda etapa está em andamento. O objetivo é analisar nove argumentos sobre a soma dos ângulos internos de um triângulo à luz do referencial teórico e investigar como licenciandos ingressantes em Matemática interpretam e avaliam tais argumentações, sob três pontos de vista distintos. Inicialmente, os participantes deveriam se colocar no lugar de um professor para avaliar cada um dos nove argumentos apresentados; em seguida, responder se eles utilizariam alguns em suas aulas. Por fim, eles deveriam responder se adotariam algum dos argumentos ao realizar um teste no Ensino Superior. Os resultados evidenciaram uma preferência pelos argumentos formais, e indicaram que a simples aparência de uma resposta associada à linguagem algébrica, às vezes, é suficiente para convencê-los, ainda que logicamente contraditória. A segunda etapa da pesquisa, pretende investigar o posicionamento dos mesmos sujeitos, agora licenciandos concluintes."},{"ano":2022,"titulo":"Investigating Programming Students Problem Comprehension Ability and Its Association With Learning Performance","autores":"Gabriel Fortes","autores_todos":["Leonardo Silva","António José Mendes","Anabela Gomes","Gabriel Fortes"],"estudantes":[],"periodico":"IEEE TRANSACTIONS ON EDUCATION","qualis":"A2","area":"Ensino (Ciências/Exatas)","temas":"Ensino de Ciências e Matemática","disciplina":"Computação","tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1109/te.2022.3204906","doi":"10.1109/te.2022.3204906","resumo":"Contribution: Students’ problem-understanding abilities and their relationship with programming learning were investigated using a methodology little explored in the existing literature. Background: Problem comprehension is an ability used during software development. Current research points to conflicting results on students’ ability to interpret problems, which calls for further research. In addition, the influence of this skill in programming learning also deserves additional studies. Research Questions: The following research questions were developed: RQ1) Can introductory programming students correctly interpret the statement of programming questions? RQ2) Is the student’s problem comprehension ability associated with creating correct programs? Methodology: Forty-eight students enrolled in an online introductory programming course participated in the investigation. Students’ problem-understanding externalizations were analyzed, and statistical tests were performed to assess the association of this ability with programming learning performance. Findings: Most students externalized a satisfactory degree of problem-understanding competency. The cases in which students’ misinterpreted the problem were associated with creating faulty software. However, a closer analysis suggests that there are other factors that must also be considered."},{"ano":2022,"titulo":"METACOGNIÇÃO EM ESTRATÉGIA AUTORREGULATÓRIA NA RESOLUÇÃO DE PROBLEMAS EM FÍSICA","autores":["Gabriel Fortes","Kátia Calligaris Rodrigues"],"autores_todos":[],"estudantes":[],"periodico":"CAMINHOS DA EDUCAÇÃO MATEMÁTICA EM REVISTA","qualis":"A4","area":"Educação","temas":"Metacognição e Autorregulação","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://periodicos.ifs.edu.br/index.php/caminhos_da_educacao_matematica/article/view/1404/1379","doi":"","resumo":""},{"ano":2022,"titulo":"Movimentos discursivos da argumentação e processos cognitivos da aprendizagem significativa no mapeamento conceitual","autores":["Kátia Calligaris Rodrigues","Sylvia De Chiaro"],"autores_todos":["Lívia Da Silva Dos Santos","Sylvia De Chiaro","Kátia Calligaris Rodrigues"],"estudantes":[],"periodico":"EID","qualis":"A2","area":"Educação","temas":["Argumentação","Aprendizagem Significativa","Formação de Professores","Desenvolvimento e Linguagem","Ensino de Ciências e Matemática"],"disciplina":"Física","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.47369/eidea-22-1-3345","doi":"10.47369/eidea-22-1-3345","resumo":"A argumentação é uma organização discursiva específica em que movimentos de justificação e negociação de perspectivas são observados. Por outro lado, a negociação de ideias também é marca da aprendizagem significativa, caracterizada pela ocorrência dos processos cognitivos de diferenciação progressiva e reconciliação integrativa. Esse artigo é parte de um estudo que se propôs a investigar a relação entre os movimentos discursivos da argumentação e os processos cognitivos da aprendizagem significativa no decurso de mapeamentos conceituais. Observamos a elaboração de mapas conceituais por dois estudantes de licenciatura em física do Centro Acadêmico do Agreste da Universidade Federal de Pernambuco em duas situações distintas: 1) na elaboração de mapas conceituais individuais e 2) na elaboração de um mapa conceitual coletivo. Essas observações foram videogravadas, transcritas e analisadas. A partir delas, encontramos indícios de que os movimentos discursivos da argumentação têm o potencial de evocar e manter os processos cognitivos da aprendizagem significativa."},{"ano":2022,"titulo":"Prejudice in visual argument","autores":"Gabriel Fortes","autores_todos":["Gabriel Fortes","Patrícia Fortes Cavalcanti de Macêdo"],"estudantes":[],"periodico":"EID","qualis":"A2","area":"Educação","temas":"Argumentação","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.47369/eidea-22-2-3434","doi":"10.47369/eidea-22-2-3434","resumo":"This article discusses different types of “argumentativeness” in three memes related to overweight jokes posted in a community of meme generation (quickmeme.com) in July 2021. We aim to show how visual argument, image rhetoric, and social prejudice devices enable the creation of “joking” memes that frame an audience's meaning-making towards prejudiced ideas. The methodological procedure was based on an analytical process of the selected memes using a theoretical framework on visual argumentation, media studies, and attitudes and beliefs around body image. The results suggest that fat body prejudice images in the memes operate in the level of persuasiveness of the audience of certain rationality through argument schemes easily recognizable by an audience."},{"ano":2022,"titulo":"Studying argumentation and education in South America: what has been advanced and what lies ahead","autores":"Gabriel Fortes","autores_todos":["Gabriel Fortes","Valentina Guzmán","Antonia Larrain"],"estudantes":[],"periodico":"ARGUMENTATION AND ADVOCACY","qualis":"Sem Qualis","area":"Educação","temas":"Argumentação","disciplina":[],"tipo":"Teórico","idioma":"Inglês","link":"https://doi.org/10.1080/10511431.2022.2138174","doi":"10.1080/10511431.2022.2138174","resumo":"With this paper, we aim to present what has been developed so far in the field of argumentation and education in South America to the best of our knowledge. However, we also aim to anticipate new trends that will arise from the challenges South American democracies face right now, and the role of collective reasoned discussion in tackling them. Traditionally argumentation studies have been proposed within three broad areas of research and practice. First, argue to learn, as the uses of argumentation practices to develop conceptual knowledge in different domains of education. Second, learn to argue by promoting argumentative practices to develop argumentative and thinking skills. Third, teacher professional development enables teachers to enact argumentation in their classrooms. From this scenario, we argue that three interrelated branches of research are the future ahead of us: studies of argumentation and citizen education using deliberative practices, cultivating virtuous intellectual habits, and the rise of deliberative teaching focused on collaborative settings designed to empower democratic values (diversity, equality, and participation). We conclude by stating that South America has helped the advancement of argumentation theory, but we still have a road ahead in developing more spaces for democratic participation."},{"ano":2022,"titulo":"UMA INVESTIGAÇÃO SOBRE A PERCEPÇÃO DE PROFESSORES COM RELAÇÃO AO ENSINO REMOTO EMERGENCIAL DE MATEMÁTICA","autores":"João Carlos Caldato Correia","autores_todos":["Erilúcia Souza da Silva","João Carlos Caldato","Marcio Vieira de Almeida","Maria Helena Monteiro Mendes Baccar","Mário Keniichi Gushima Moura"],"estudantes":[],"periodico":"REVISTA PARANAENSE DE EDUCAÇÃO MATEMÁTICA","qualis":"A2","area":"Ensino (Ciências/Exatas)","temas":["Metodologias Ativas e Tecnologia","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.33871/22385800.2022.11.24.244-266","doi":"10.33871/22385800.2022.11.24.244-266","resumo":"\"Esta pesquisa teve o objetivo de identificar aspectos das práticas de ensino de professores que lecionaram Matemática durante certo período da pandemia da COVID-19, particularmente os recursos e as dinâmicas utilizados no ensino remoto emergencial, bem como investigar as percepções desses professores sobre os aspectos positivos e negativos dessa utilização. Para isso, elaborou-se um questionário online que foi respondido por cem professores. A partir da análise qualitativa dos dados, inspirada na análise de conteúdo de Laurence Bardin, concluiu-se, dentre outros, que: os professores utilizaram diferentes estratégias para se aproximar dos alunos, mesmo que remotamente; o acesso às atividades e aulas não foi uniforme pelos alunos; metodologias próprias do ensino híbrido foram utilizadas e houve a percepção, por parte dos docentes, da necessidade de formação continuada referente a tecnologias digitais. Dessa forma, a maioria dos participantes reconheceu a importância do uso de recursos e dinâmicas do ensino remoto emergencial no retorno do ensino presencial.\""},{"ano":2022,"titulo":"Uma investigação sobre percepções de professores que ensinam Matemática em relação às práticas avaliativas durante o ensino remoto emergencial","autores":"João Carlos Caldato Correia","autores_todos":["João Carlos Caldato","Erilúcia Souza da Silva","Maria Helena Monteiro Mendes Baccar","Mário Keniichi Gushima Moura"],"estudantes":[],"periodico":"REVISTA DE EDUCAÇÃO MATEMÁTICA","qualis":"A1","area":"Ensino (Ciências/Exatas)","temas":["Formação de Professores","Metodologias Ativas e Tecnologia","Avaliação e Trajetórias","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.37001/remat25269062v19id668","doi":"10.37001/remat25269062v19id668","resumo":"Este artigo é parte de uma pesquisa mais ampla que teve como objetivo identificar aspectos das práticas de ensino de professores que lecionaram Matemática durante certo período da pandemia da Covid-19. Em particular, neste estudo investigam-se as práticas avaliativas desses docentes, assim como, as suas percepções sobre os pontos positivos e negativos dessas práticas e as possíveis alterações que eles pretendem implementar no retorno do ensino presencial. Assim, elaborou-se um questionário online que foi respondido por cem professores. Para a análise qualitativa dos dados, adotou-se a análise de conteúdo de Laurence Bardin. A partir das respostas dos professores, os principais resultados foram: a reprodução de estratégias avaliativas do ensino presencial para o ensino remoto; a ausência de pontos positivos da avaliação durante o ensino remoto; a não intenção de manutenção das tecnologias digitais para a avaliação no retorno às aulas presenciais. Por fim, observou-se que o ensino remoto serviu para alguns como um meio de ressignificação da avaliação em Matemática."},{"ano":2022,"titulo":"Uso do jogo didático -Adivinha Qual?- como evento propício à revisitação do erro e da tomada de consciência de conceitos de química orgânica","autores":"Jose Ayron Lira dos Anjos","autores_todos":["José Ayron Lira dos Anjos","Joao Roberto Rátis Tenório Da Silva","Ana Paula Freitas Da Silva","Ricardo Lima Guimarães"],"estudantes":["João Paulo Silva","Paula Eduarda Nunes da Silva"],"periodico":"REVISTA BRASILEIRA DE ENSINO DE CIÊNCIA E TECNOLOGIA","qualis":"A2","area":"Ensino (Ciências/Exatas)","temas":["Metacognição e Autorregulação","Metodologias Ativas e Tecnologia","Desenvolvimento e Linguagem","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.3895/rbect.v15n1.14786","doi":"10.3895/rbect.v15n1.14786","resumo":"Buscando estimular alternativas que se contraponham a uma realidade de ensino que leva os estudantes brasileiros, sobretudo de escolas públicas, a um conhecimento deficitário a Teachers College-Columbia University em parceria com a Fundação Lemann investiu no fortalecimento da atuação de pesquisadores brasileiros lançando o edital “Researching Teaching and Learning: An Equity Imperative for Teacher Education”. Contemplado nesse edital, o Núcleo de Investigações, Desenvolvimento e Estudo de Jogos no Ensino (NIDEJE) se propôs a investigar como as situações de interação discursiva propiciadas pelo uso de jogos didáticos podem ser um fator de mudança de um cenário de ensino, em que dúvidas e erros são desconsiderados como oportunidades de (re)significação de entendimentos. Para tal foi aplicado o jogo didático “Adivinha Qual?”, em uma escola da rede pública de ensino médio do agreste pernambucano, sendo a primeira aplicação do jogo didático com a participação exclusiva de estudantes que apresentavam dificuldades no conteúdo de funções orgânicas e a segunda aplicação com grupos compostos com alguns estudantes que apresentavam dificuldades e outros que tinham um melhor rendimento escolar na disciplina de química. A externalização dos pensamentos dos alunos em seus planejamentos, discussões, e reflexões ocorridas no decorrer do jogo, foram registradas e posteriormente analisadas por meio da análise microgenética. Deste modo, analisamos as interações discursivas propiciadas a partir"},{"ano":2021,"titulo":"A sucessão florestal e a arquitetura vegetal influenciam a herbivoria em Cenostigma pyramidale em Floresta Tropical Sazonal Seca?","autores":"José Antônio Bezerra de Oliveira","autores_todos":["José Antônio Bezerra de Oliveira","Jarcilene Silva Almeida"],"estudantes":"Sandrielly Almeida Lins da Silva","periodico":"JOURNAL OF ENVIRONMENTAL ANALYSIS AND PROGRESS","qualis":"B2","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.24221/jeap.6.4.2021.3616.352-362","doi":"10.24221/jeap.6.4.2021.3616.352-362","resumo":"A herbivoria pode ser influenciada pelas características defensivas vegetais e pelo terceiro nível trófico bem como pela arquitetura da planta. A Caatinga possui áreas com diferentes idades de regeneração natural após abandono. O objetivo foi avaliar se o estádio sucessional de regeneração e arquitetura vegetal influenciam a herbivoria. Cenostigma pyramidale foi usada como planta modelo por ocorrer nos três estádios sucessionais (inicial, intermediário e tardio). Foram amostrados insetos herbívoros e aranhas associados e mensuradas as taxas de herbivoria foliar, a arquitetura vegetal, os índices de esclerofilia. Foram coletados um total 241 insetos herbívoros de 21 morfoespécies e 116 aranhas. A abundância total de insetos foi afetada negativamente pela estação seca. A taxa de herbivoria e abundância de herbívoros foi maior no estádio inicial, no entanto o número de aranhas foi menor e taxa de área foliar perdida maior no estádio intermediário. A abundância de aranhas afetou negativamente as taxas de herbivoria. A biomassa de parte aérea apresentou uma relação positiva com a abundância de insetos sugadores. Assim, pode-se prever que o estágio sucessional, a arquitetura vegetal e predadores aracnídeos podem estar relacionados com a herbivoria em florestas tropicais sazonalmente secas."},{"ano":2021,"titulo":"ARGUMENTAÇÃO NO ENSINO DE MATEMÁTICA: UM CAMINHO A DEBATIBILIDADE","autores":"Tais de Oliveira Silva","autores_todos":"Taís de Oliveira Silva","estudantes":[],"periodico":"EXPERIÊNCIAS EM ENSINO DE CIÊNCIAS (UFRGS)","qualis":"A3","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Pensamento Crítico e Reflexivo","Desenvolvimento e Linguagem","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Teórico","idioma":"Português","link":"https://fisica.ufmt.br/eenciojs/index.php/eenci/article/download/808/779","doi":"","resumo":"A argumentacao e concebida como estrategia didatica potencialmente discursiva e util para o ensino das ciencias. Objetivando analisar seu impacto na constituicao conceitual dos conteudos matematicos, bem como sua potencialidade na formacao critica e reflexiva dos alunos do 6° ano do ensino fundamental, elaborou-se um problema, por meio da pesquisa acao, referente aos numeros racionais, no qual os estudantes tinham a incumbencia de soluciona-lo durante um debate. O problema de acao consistia na discussao acerca da viabilidade de se abrir um supermercado cujos precos estivessem em numeros fracionarios e decimais. Com base nas analises, foi possivel identificar que a atividade promoveu a construcao coletiva do conhecimento conceitual matematico, alem de possibilitar o progresso dos discentes em habilidades argumentativas, cognitivas, reflexivas e critica."},{"ano":2021,"titulo":"Argumentação na sala de aula: refletindo criticamente sobre a descriminalização do aborto em uma vivência de prática argumentativa","autores":["Kátia Calligaris Rodrigues","Sylvia De Chiaro"],"autores_todos":["Carolina Santos de Miranda","Brunna Stephanye Macêdo Coelho de Lima","Sylvia De Chiaro","Kátia Calligares Rodrigues"],"estudantes":"Brunna Stephanye Macêdo Coelho de Lima","periodico":"EDUCAÇÃO ON-LINE (PUCRJ)","qualis":"A4","area":"Educação","temas":["Argumentação","Metacognição e Autorregulação","Formação de Professores","Pensamento Crítico e Reflexivo","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.36556/eol.v16i37.829","doi":"10.36556/eol.v16i37.829","resumo":"O objetivo do presente estudo foi analisar a potencialidade argumentativa de uma prática pedagógica e seu alcance em promover uma reflexão crítica, típica de um funcionamento metacognitivo. Partindo de uma compreensão da argumentação como um recurso discursivo de natureza dialógica, dialética e epistêmica, uma prática pedagógica argumentativa sobre a descriminalização do aborto foi aplicada em uma turma de formação inicial de professores da Universidade Federal de Pernambuco (UFPE). As análises denotaram a presença dos elementos de um ciclo argumentativo – argumento (A), contra-argumento (CA) e resposta (R), mostrando assim a possibilidade de fazer emergir a argumentação em sala de aula, a partir de uma prática pedagógica intencionalmente elaborada para esse fim. Diferentes formas de monitoramento do pensamento - mantenedora, elaboradora e reconstrutora - também foram encontradas nas análises. O monitoramento do pensamento é um movimento que caracteriza um funcionamento metacognitivo, por levar os indivíduos a refletirem sobre seus próprios pensamentos. Nesse sentido, foi possível concluir que a construção de conhecimento ocorrida por via da argumentação se deu de forma crítica e reflexiva. O objetivo do presente estudo foi analisar a potencialidade argumentativa de uma prática pedagógica e seu alcance em promover uma reflexão crítica, típica de um funcionamento metacognitivo. A prática pedagógica argumentativa sobre a descriminalização do aborto foi aplicada em uma turma de"},{"ano":2021,"titulo":"CONTRIBUIÇÕES DE UMA PROPOSTA DIDÁTICA NA PERSPECTIVA DA EDUCAÇÃO CIENTÍFICA BASEADA EM PROJETO, A PARTIR DA TEMÁTICA DA HIPERTENSÃO ARTERIAL","autores":"Jose Ayron Lira dos Anjos","autores_todos":["José Ayron Lira dos Anjos","Janaína Maria da Silva","Maria Maciel Rocha dos Anjos"],"estudantes":["Daniela Maria Do Espirito Santo e Silva","Maria Maciel Rocha dos Anjos"],"periodico":"EXPERIÊNCIAS EM ENSINO DE CIÊNCIAS (UFRGS)","qualis":"A3","area":"Educação","temas":"Desenvolvimento e Linguagem","disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://fisica.ufmt.br/eenciojs/index.php/eenci/article/download/914/812","doi":"","resumo":"A Alfabetizacao Cientifica torna os individuos capacitados a ler o mundo a luz dos conhecimentos de ciencias e articula-los a outros saberes na transformacao da realidade. A Educacao Cientifica baseada em projetos parte de uma tematica pertinente aos estudantes e os instiga, por meio de acoes educativas, a significacao do conhecimento escolar e ao protagonismo na resolucao de problemas. A tematica abordada neste trabalho trata da hipertensao arterial, um problema social pouco abordado na esfera educativa de jovens e adolescentes. Assim, objetivou-se analisar as contribuicoes de uma proposta didatica de Educacao Cientifica Baseada em Projeto no desenvolvimento do pensamento cientifico em estudantes partindo da tematica da Hipertensao Arterial. Tendo como alvo alunos do 2o ano do ensino medio a metodologia foi organizada em seis momentos, que proporcionaram situacoes de aprendizagem favorecedoras da compreensao de conceitos e fazeres. A culminância do projeto foi a realizacao de uma atividade de divulgacao cientifica realizada pelos alunos, para a comunidade escolar, em que os conhecimentos construidos ao longo do processo foram mobilizados para elaborar formas de explicar a tematica da hipertensao arterial. A observacao da vivencia sugere o inicio do processo de construcao do conhecimento pelos alunos, bem como mostra indicios da alfabetizacao cientifica."},{"ano":2021,"titulo":"Deliberative Teaching as an Emergent Field: The Challenge of Articulating Diverse Research Agendas to Promote Educational Experiences for Citizenship","autores":"Gabriel Fortes","autores_todos":["Antonia Larrain","Gabriel Fortes","María Teresa Rojas"],"estudantes":[],"periodico":"FRONTIERS IN PSYCHOLOGY","qualis":"A2","area":"Educação","temas":"Argumentação","disciplina":[],"tipo":"Teórico","idioma":"Inglês","link":"https://doi.org/10.3389/fpsyg.2021.660825","doi":"10.3389/fpsyg.2021.660825","resumo":"Democracies are increasingly dependent upon sustainable citizenship, that is, active participation and engagement with the exercising of rights in a field of plural interests, often contradictory and in conflict. This type of citizenship requires not only social inclusion, habits of knowledge, and evidence-based reasoning but also argumentation skills, such as the individual and social capacity to dispute and exercise individual and social rights, and to deal peacefully with sociopolitical conflict. There is empirical evidence that educational deliberative argumentation has a lasting impact on the deep and flexible understanding of knowledge, argumentation skills, and political and citizenship education. However, these three trends of research have developed independently with insufficient synergy. Considering the relevance of deliberative education for contemporaneous democracies and citizenship, in this paper we seek to converge in a field of interlocution, calling it deliberative teaching. Our aim is to propose a way to increase the dialog and collaboration between the diffuse literature on argumentation and education, highlighting both the main theoretical and empirical gaps and challenges that remain and the possibilities to advance our knowledge and the educational impact that this integrating field could offer."},{"ano":2021,"titulo":"REFLEXÕES SOBRE O PLANEJAMENTO DE ENSINO A PARTIR DA ELABORAÇÃO DE MAPAS CONCEITUAIS","autores":"Kátia Calligaris Rodrigues","autores_todos":[],"estudantes":[],"periodico":"CURRÍCULO & DOCÊNCIA","qualis":"B2","area":"Educação","temas":"Aprendizagem Significativa","disciplina":[],"tipo":"Teórico","idioma":"Não informado","link":"https://periodicos.ufpe.br/revistas/CD/article/view/250119","doi":"","resumo":""},{"ano":2021,"titulo":"Raciocínio Argumentativo em Matemática no PISA e na BNCC: uma investigação com estudantes da Educação Básica","autores":"João Carlos Caldato Correia","autores_todos":["Carlos Augusto Aguilar Júnior","João Carlos Caldato"],"estudantes":[],"periodico":"BOLETIM GEPEM (ONLINE)","qualis":"A2","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Políticas e Equidade Educacional","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.4322/gepem.2022.008","doi":"10.4322/gepem.2022.008","resumo":"O objetivo deste artigo é investigar como os estudantes, a partir dos anos finais do Ensino Fundamental, raciocinam e argumentam sobre algumas afirmações matemáticas. Para isso, inicialmente foram analisados documentos oficiais, uma vez que se buscou articular aproximações entre a BNCC e a matriz do PISA. Inspirados em uma das questões-exemplo da matriz do PISA 2021/2022, empreendemos uma pesquisa exploratória, por meio de um questionário virtual, respondido por 52 alunos da Educação Básica. Dentre os resultados obtidos por meio de uma análise quanti-qualitativa inspirada na tipologia de prova de Nicolas Balacheff, constatou-se que os argumentos apresentados, em grande parte, eram pautados em verificações empíricas. Consideramos que a abordagem destas questões em avaliações de largo alcance estimula o trabalho pedagógico voltado à construção das habilidades de argumentar e demonstrar, importantes tanto para o desenvolvimento em Matemática como também para sua atuação num contexto social mais ampliado."},{"ano":2021,"titulo":"Survival of the kingdoms: uma proposta de jogo teatral para o ensino de Química","autores":"Jose Ayron Lira dos Anjos","autores_todos":["Luís Henrique Raimundo","ANNA CAROLLINY DA SILVA","Maurício Mateus da Silva Tavares","Arthur Cristopher de Souza","José Ayron Lira Dos Anjos","Maria Juliana Mendes da Silva","Josivaldo Almeida da Silva"],"estudantes":"Sandrielly Almeida Lins da Silva","periodico":"REVISTA DEBATES EM ENSINO DE QUÍMICA","qualis":"A1","area":"Ensino (Ciências/Exatas)","temas":["Formação de Professores","Metodologias Ativas e Tecnologia","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.29327/eneqpe2020.244975","doi":"10.29327/eneqpe2020.244975","resumo":"Pesquisas em ensino de quimica orientam que a diversidade na dinâmica dos recursos didaticos para a apresentacao dos conteudos favorece a construcao do conhecimento com significado. E justifica tal afirmacao no entendimento de que um maior nivel de interacao com o objeto pedagogico e/ou com seus pares propicia ao aluno se indagar, criar e socializar sentidos e assim construir o saber criticamente. Com esse objetivo propomos nesse trabalho o jogo didatico Survival of the Kingdoms um jogo teatral da categoria action live, que permite ao aluno acessar um ambiente que lhe desafiara a criar, investigar, compartilhar saberes, construir e (re)construir conhecimentos, inquietados pelos desafios propostos e apoiados nas reflexoes propiciadas por meio da socializacao de entendimentos. O Survival of the Kingdoms foi criado por estudantes do curso de Licenciatura em Quimica e aplicado em uma escola da Rede Estadual no interior do Agreste Pernambucano, a fim de proporcionar aos alunos do Terceiro Ano do Ensino Medio situacoes didaticas diferenciadas e estimulantes ao aprendizado. Sua jogabilidade consiste em uma perspectiva teatral construida a partir de um enredo medieval, tendo como tematica alguns conteudos de quimica organizados pelas tematicas: agua, fogo, terra e ar, voltados a uma revisao dos conteudos de quimica para o vestibular. Como principal resultado da validacao do jogo didatico observou-se uma maior interacao, e engajamento de todos os alunos participantes na tentativa de s"},{"ano":2020,"titulo":"A discussion on the concepts of goal, skill and competence in the high school BNCC","autores":"Kátia Calligaris Rodrigues","autores_todos":["Leonardo Ferreira Rufino","Saulo José de Barros Júnior","Kátia Silva Cunha","Kátia Calligaris Rodrigues"],"estudantes":[],"periodico":"CURRÍCULO & DOCÊNCIA","qualis":"B2","area":"Educação","temas":"Políticas e Equidade Educacional","disciplina":[],"tipo":"Teórico","idioma":"Inglês","link":"https://periodicos.ufpe.br/revistas/CD/article/download/249557/37710","doi":"","resumo":"No Brasil, o planejamento do curriculo da Educacao Basica e sempre muito discutido por teoricos como Lopes e Macedo por exemplo, uma dessas discussoes e referente aos conceitos de objetivos, habilidade e competencias e a confusao na pratica e no uso desses conceitos. Outro alvo de criticas no campo do curriculo e o novo documento da Base Nacional Comum Curricular (BNCC), pois passou a nortear os curriculos de escolas de todo pais. Assim, este trabalho busca uma analise comparativa entre a forma como os objetivos, habilidades e competencias sao utilizadas na BNCC e como esses se apresentam nas teorias que iniciaram e ainda discutem sobre estas definicoes. Utilizando as visoes de Tyler, Perrenoud; outros autores que os sucedem, e que estabeleceremos uma relacao sobre como as definicoes apresentadas no documento da BNCC referente a esses conceitos, possibilitam o levantamento de criticas ao que hoje e exigido dos alunos de ensino basico brasileiro.\r\nPalavras-chave: Habilidades, Objetivos, Competencias, Curriculo, BNCC"},{"ano":2020,"titulo":"A resolução de problemas como organizador prévio para a Aprendizagem Significativa Crítica na Educação Básica","autores":"José Antônio Bezerra de Oliveira","autores_todos":[],"estudantes":[],"periodico":"INTERFACE","qualis":"Sem Qualis","area":"Educação","temas":"Aprendizagem Significativa","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://scholar.google.com/scholar?q=A%20resolu%C3%A7%C3%A3o%20de%20problemas%20como%20organizador%20pr%C3%A9vio%20para%20a%20Aprendizagem%20Significativa%20Cr%C3%ADtica%20na%20Educa%C3%A7%C3%A3o%20B%C3%A1sica","doi":"","resumo":""},{"ano":2020,"titulo":"ARGUMENTACIÓN Y EDUCACIÓN: UN CAMPO DIVERSO, TENSIONADOY TENSIONANTE EN EMERGENCIA","autores":"Gabriel Fortes","autores_todos":[],"estudantes":[],"periodico":"COGENCY: JOURNAL OF REASONING AND ARGUMENTATION","qualis":"B2","area":"Educação","temas":"Argumentação","disciplina":[],"tipo":"Teórico","idioma":"Não informado","link":"https://cogency.udp.cl/index.php/cogency/article/view/353/147","doi":"","resumo":""},{"ano":2020,"titulo":"AUTORREGULAÇÃO DA APRENDIZAGEM NA ESTRATÉGIA DE ESCOLHA E RESOLUÇÃO DE PROBLEMAS EM FÍSICA: UM ESTUDO EXPLORATÓRIO","autores":"Kátia Calligaris Rodrigues","autores_todos":["Everaldo Sebastião da Silva","Kátia Calligaris Rodrigues"],"estudantes":[],"periodico":"EXPERIÊNCIAS EM ENSINO DE CIÊNCIAS (UFRGS)","qualis":"A3","area":"Educação","temas":["Metacognição e Autorregulação","Formação de Professores","Pensamento Crítico e Reflexivo"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://fisica.ufmt.br/eenciojs/index.php/eenci/article/download/715/683","doi":"","resumo":"Esse artigo apresenta um estudo sobre a autorregulacao da aprendizagem a partir da insercao da estrategia de Escolha e Resolucao de Problemas (ERP) em um curso de formacao inicial de professores de Fisica em uma Instituicao Publica de Ensino Superior do nordeste Brasileiro. A insercao da ERP, em uma disciplina obrigatoria de Fundamentos de Fisica, teve o objetivo de provocar processos reflexivos e autorregulatorios no docente em formacao. A fim de verificar esses processos, foi elaborado e implementado um questionario de acompanhamento da estrategia de ERP, tendo como referencial teorico os estudos de Zimmerman e Pintrich para a Autorregulacao da Aprendizagem. Os resultados aqui discutidos focam em tres elementos: a motivacao, a aprendizagem e a resolucao de problemas. Os resultados apontam que a estrategia de ERP, aliada a aplicacao do questionario, promoveu uma melhora significativa desses elementos ao longo do periodo da disciplina. Ha evidencias do desenvolvimento de processos autorregulatorios especificos segundo a perspectiva de Zimmerman. Implicacoes para a formacao de professores tambem sao discutidas."},{"ano":2020,"titulo":"Argumentation in chemical teaching: Construction about the concept of atomic models","autores":"Tais de Oliveira Silva","autores_todos":["Taís de Oliveira Silva","Karla Kilma Correia","Camilla Maria Dos Santos","Klebson Nelson da Silva"],"estudantes":[],"periodico":"CURRÍCULO & DOCÊNCIA","qualis":"B2","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Inglês","link":"https://periodicos.ufpe.br/revistas/CD/article/download/248105/36528","doi":"","resumo":"A argumentacao e um processo dialogico que tem por finalidade a construcao do conhecimento. Logo, e compreendida como uma estrategia didatica util para o ensino de Quimica. Seu carater dialogico e sua dinâmica possibilitam desenvolver a elaboracao coletiva da aprendizagem. Por isso, torna-se ainda mais viavel sua utilizacao no ensino da Quimica devido a abstracao que essa ciencia abarca em sua essencia e que normalmente e ensinado com ilustracoes que favorecem o aparecimento de obstaculos epistemologicos. Sendo assim, este trabalho tem por objetivo investigar de que forma a argumentacao pode auxiliar os estudantes na compreensao do desenvolvimento dos modelos atomicos ao longo de debates sobre questoes cientificas, que envolvem praticas relacionadas ao processo de construcao e reformulacao de conceitos, ancoradas na perspectiva dialogicas proposta por Leitao (2011).\r\nPalavras-chave:Argumentacao,Ensinode Quimica, Modelos."},{"ano":2020,"titulo":"Argumentação e Prova em Matemática: uma análise dos itens públicos do PISA 2012","autores":"João Carlos Caldato Correia","autores_todos":["João Caldato","Carlos Augusto Aguilar Júnior"],"estudantes":[],"periodico":"REVISTA BAIANA DE EDUCAÇÃO MATEMÁTICA","qualis":"B1","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Políticas e Equidade Educacional","Avaliação e Trajetórias","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.47207/rbem.v1i.10321","doi":"10.47207/rbem.v1i.10321","resumo":"Neste artigo, o objetivo é analisar os itens públicos do Programa Internacional de Avaliação dos Estudantes (PISA, em inglês) de 2012 que versem sobre argumentação e prova em Matemática. Estes itens exploram os três processos matemáticos (formular, empregar e interpretar), fundamentais para o desenvolvimento da capacidade de raciocinar e argumentar, e definem o letramento matemático segundo a matriz de referência do PISA. Na abordagem teórico-metodológica, recorremos a trabalhos referenciados na literatura que discutem as funções da prova, bem como apresentam outros trabalhos exploratórios envolvendo estudantes e professores. O estudo se caracteriza por uma pesquisa documental, de cunho qualitativo. No levantamento realizado na base de questões públicas disponível no site do Instituto Nacional de Estudos e Pesquisas Educacionais Anísio Teixeira (INEP), selecionamos 10 itens que atendiam a critérios previamente estabelecidos e procedemos à análise de três destes itens, um de cada processo matemático, à luz dos referenciais que discutem os papéis da prova. Os resultados mostram que os itens buscam mobilizar no estudante habilidades que tencionam o desenvolvimento do raciocínio lógico, conforme estabelecido na BNCC. A título de conclusões parciais, consideramos que a abordagem dessas questões em avaliações de largo alcance, bem como em avaliações institucionais (realizadas pela própria escola), estimula o trabalho pedagógico voltado à construção das habilidades de argumentar e d"},{"ano":2020,"titulo":"Caracterização e aplicação de uma Unidade de Ensino Potencialmente Significativa sobre Locomoção Humana","autores":"José Antônio Bezerra de Oliveira","autores_todos":[],"estudantes":[],"periodico":"INTERFACE","qualis":"Sem Qualis","area":"Educação","temas":"Aprendizagem Significativa","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://scholar.google.com/scholar?q=Caracteriza%C3%A7%C3%A3o%20e%20aplica%C3%A7%C3%A3o%20de%20uma%20Unidade%20de%20Ensino%20Potencialmente%20Significativa%20sobre%20Locomo%C3%A7%C3%A3o%20Humana","doi":"","resumo":""},{"ano":2020,"titulo":"Construção de significados e ambiguidades na supervisão de estágio em psicologia","autores":"Nádia Oliveira da Silva","autores_todos":["Nádia Oliveira da Silva","Marina Assis Pinheiro","Candy Estelle Laurendon"],"estudantes":[],"periodico":"PSICOLOGIA-UNIVERSIDADE DE SP-USP (IMPRESSO)","qualis":"A2","area":"Psicologia","temas":["Formação de Professores","Psicologia e Subjetividade","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.1590/0103-6564e200064","doi":"10.1590/0103-6564e200064","resumo":"Resumo Na formação de psicólogos, o tripé supervisão-estágio-ensino é fundamental para o desenvolvimento de competências profissionais. Todavia a relação estreita entre estas três esferas ocasiona, por vezes, uma compreensão nebulosa sobre a práxis concernente a cada um destes campos. À luz do dialogismo bakhtiniano e da intersubjetividade, este artigo visa a analisar a construção de significados sobre supervisão de estágio, por meio das ambiguidades que enlaçam esta atividade. Foi possível analisar que as ambiguidades permeadas pelo tripé formativo ocasionam tensões nas relações intersubjetivas, sendo balizadoras na construção de novos significados sobre a atividade de supervisão. Estes significados são tecidos pela negociação com as outridades que permeiam essa atividade formativa e pelo contexto em que são realizadas. Isto posto, estudos desta natureza propiciam uma compreensão mais ampla sobre conhecimentos teóricos/práticos concernentes ao campo da supervisão, o que pode ensejar a construção de estratégias facilitadoras na formação de psicólogos."},{"ano":2020,"titulo":"Diseño De un programa De formación Docente para el Desarrollo De conocimiento peDagógico De conteniDo De la argumentación","autores":"Gabriel Fortes","autores_todos":[],"estudantes":[],"periodico":"COGENCY: JOURNAL OF REASONING AND ARGUMENTATION","qualis":"B2","area":"Educação","temas":"Argumentação","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.32995/cogency.v12i2.365","doi":"10.32995/cogency.v12i2.365","resumo":"Durante las ltimas dcadas, la argumentacin ha ganado importancia central como parte de los objetivos educativos del siglo XXI. Est ampliamente aceptado que la argumentacin es una caracterstica clave para el aprendizaje. Si bien se considera que los resultados de los estudiantes en el aprendizaje y el razonamiento se asocian positivamente con la argumentacin, los contextos del aula an reproducen las ideas tradicionales de enseanza-aprendizaje, tal como la pedagoga centrada en adultos, orientada al individuo y basada en el contenido. Un actor clave para cambiar esto es el profesorado, sin embargo, se sabe menos sobre cmo desarrollar el conocimiento docente de la argumentacin y cmo utilizarlo en el contexto del aula. En este estudio presentamos el primer ciclo de una de investigacin design-based dividido en cuatro fases: 1) explorar el problema; 2) disear una solucin; 3) implementar la solucin; y 4) evaluacin y rediseo. En cada fase realizamos diferentes procedimientos para una elaborar propuesta de solucin rigurosa: as, 1) presentamos una revisin bibliogrfica no exhaustiva del desarrollo profesional docente en argumentacin, 2) con ella construimos un programa de formacin docente en argumentacin;"},{"ano":2020,"titulo":"Estratégias didáticas para o ensino de resíduos sólidos nas perspectivas da Educação Ambiental Crítica e Aprendizagem Significativa Crítica","autores":"José Antônio Bezerra de Oliveira","autores_todos":["José Antônio Bezerra de Oliveira","Andreza Ximenes de Araújo","Kátia Aparecida da Silva Aquino"],"estudantes":[],"periodico":"EDUCAÇÃO AMBIENTAL EM AÇÃO","qualis":"Sem Qualis","area":"Educação","temas":["Aprendizagem Significativa","Educação Ambiental"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://www.revistaea.org/artigo.php?idartigo=4010","doi":"","resumo":"Esse estudo objetivou elaborar estrategias para o ensino de residuos solidos, na perspectiva da Educacao Ambiental Critica, para promocao de uma aprendizagem significativa. Apos estruturacao a aplicacao das atividades para estudantes do Ensino Medio, a aprendizagem deles foi analisada via mapas conceituais."},{"ano":2020,"titulo":"JOGOS COOPERATIVOS E ARGUMENTAÇÃO: POTENCIALIDADES PARA A PROMOÇÃO DO PENSAMENTO CRÍTICO E REFLEXIVO NO ENSINO DE MATEMÁTICA","autores":["Carlos Antonio da Silva Lopes","Kátia Calligaris Rodrigues","Sylvia De Chiaro"],"autores_todos":["Carlos Antonio da Silva Lopes","Kátia Calligaris Rodrigues","Sylvia De Chiaro"],"estudantes":[],"periodico":"REVISTA DE ENSINO DE CIÊNCIAS E MATEMÁTICA (RENCIMA)","qualis":"A1","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo","Desenvolvimento e Linguagem","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.26843/rencima.v11i3.2293","doi":"10.26843/rencima.v11i3.2293","resumo":"O presente artigo tem como principal objetivo discutir as potencialidades de jogos em uma perspectiva cooperativa para a promoção de processos argumentativos em sala de aula, isto pensado com o intuito de propiciar o desenvolvimento do pensamento crítico e reflexivo no ensino de Matemática. Para tanto, se optou por uma pesquisa de cunho bibliográfico para levantamento e sistematização dos conceitos acerca dos temas envolvidos na pesquisa a fim de descrever essas potencialidades educativas, e, concomitantemente, realizamos análises dos documentos curriculares oficiais (Nacionais e regionais) visando identificar o que propõem os mesmos no que concerne ao ensino da Matemática. Descrevemos que, em todos os documentos analisados, a cooperação e o pensamento crítico são propostas para o trabalho em sala de aula, e, em seguida, justificamos as correlações das possíveis potencialidades dos Jogos Cooperativos (JC) para promover os processos argumentativos de acordo com os autores pesquisados. Concluímos que o professor, por meio de ações discursivas específicas, convicto da potencialidade da Argumentação e utilizando um jogo na perspectiva cooperativa, possibilitará aos alunos tornarem-se indivíduos críticos e reflexivos."},{"ano":2020,"titulo":"Jogos Cooperativos e Argumentação: Caminhos para uma Formação Crítica e Reflexiva de Licenciandos em Matemática","autores":["Carlos Antonio da Silva Lopes","Sylvia De Chiaro"],"autores_todos":["Carlos Antonio da Silva Lopes","Sylvia De Chiaro"],"estudantes":[],"periodico":"JORNAL INTERNACIONAL DE ESTUDOS EM EDUCAÇÃO MATEMÁTICA","qualis":"A3","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Formação de Professores","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.17921/2176-5634.2020v13n3p255-266","doi":"10.17921/2176-5634.2020v13n3p255-266","resumo":"ResumoO presente artigo se propõe a analisar o impacto de um curso de extensão sobre as relações entre jogos cooperativos e argumentação para uma prática crítica e reflexiva de licenciandos de Matemática de uma Universidade Federal de ensino superior. Para cada momento do curso foram desenvolvidas atividades que permitiram que os 05 licenciandos participantes tivessem contato tanto com os pressupostos teóricos sobre os jogos cooperativos e argumentação, como também vivenciassem atividades práticas que os mobilizaram na utilização dos conhecimentos adquiridos para a construção de um jogo cooperativo-argumentativo como produto final. Ao analisar os dados pudemos concluir que os licenciandos conseguiram desenvolver suas potencialidades cooperativas e argumentativas e foram capazes de elaborar um jogo que denotou a capacidade dos mesmos de pensar em como fazer emergir e manter a argumentação em um contexto cooperativo. Assim, além do curso de extensão ter contribuído para a formação crítica e reflexiva dos licenciandos envolvidos, a experiência formativa pela qual passaram ajudou-os na promoção de situações potencializadoras de um aprendizado igualmente crítico e reflexivo em suas salas de aula.&#x0D; Palavras-chave: Argumentação. Jogos Cooperativos. Pensamento Crítico-Reflexivo. Formação Docente. Educação Matemática.&#x0D; AbstractThis article aims to analyze the impact of an extension course about the relationship between cooperative games and argumentation, in order to offer c"},{"ano":2020,"titulo":"MAPEAMENTO CONCEITUAL NA NEGOCIAÇÃO DE SIGNIFICADOS: UNINDO ASPECTOS TÉCNICOS E AÇÕES ESTIMULANTES NO ESTUDO DE CÁLCULO I","autores":"Kátia Calligaris Rodrigues","autores_todos":[],"estudantes":[],"periodico":"CAMINHOS DA EDUCAÇÃO MATEMÁTICA EM REVISTA","qualis":"A4","area":"Ensino (Ciências/Exatas)","temas":["Aprendizagem Significativa","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://periodicos.ufpe.br/revistas/CD/article/view/250062","doi":"","resumo":""},{"ano":2020,"titulo":"Profesores: ¿qué seres humanos queremos ayudar a formar? Punto de partida para la defensa de la argumentación en la formación docente","autores":"Sylvia De Chiaro","autores_todos":[],"estudantes":[],"periodico":"REVISTA IBEROAMERICANA DE ARGUMENTACIÓN","qualis":"A2","area":"Educação","temas":["Argumentação","Metacognição e Autorregulação","Pensamento Crítico e Reflexivo"],"disciplina":[],"tipo":"Teórico","idioma":"Espanhol","link":"https://doi.org/10.15366/ria2020.20.013","doi":"10.15366/ria2020.20.013","resumo":"This text is a concern with the formation of critical-reflective citizens, belonging to a complex world that continuously imposes positions on different dilemmas. We understand that if an educator feels imbued with this unease, it will be part of his concerns to plan pedagogical practices that favor an equally critical and reflective knowledge construction. Argumentation in education has been proposed as an interesting path in this sense, directly impacting the reflection on teacher education. In a specific way, this article proposes to think about argumentation in educational environments, especially in teacher training courses in a double dimension: argue to learn and learn to argue. For this, in addition to reflections on the potential of argumentative discourse for a critical and significant construction of knowledge from a reflexive, metacognitive and self-regulating functioning, we also find here practical feasible proposals for the incorporation of argumentation in teacher education."},{"ano":2020,"titulo":"UMA ANÁLISE SOBRE O USO DA TEORIA DA APRENDIZAGEM SIGNIFICATIVA NO ENSINO DE QUÍMICA EM TRABALHOS CIENTÍFICOS","autores":"Jose Ayron Lira dos Anjos","autores_todos":[],"estudantes":[],"periodico":"APRENDIZAGEM SIGNIFICATIVA EM REVISTA","qualis":"C","area":"Ensino (Ciências/Exatas)","temas":["Aprendizagem Significativa","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Teórico","idioma":"Não informado","link":"https://www.if.ufrgs.br/asr/artigos/Artigo_ID177/v10_n1_a2020.pdf","doi":"","resumo":""},{"ano":2019,"titulo":"A ARGUMENTAÇÃO PRESENTE NA CONSTRUÇÃO DE MAPAS CONCEITUAIS COMO PROPULSORA DE UMA APRENDIZAGEM SIGNIFICATIVA CRÍTICA / THE ARGUMENTATION PRESENT IN CONSTRUCTION OF CONCEPTUAL MAPS AS DRIVER OF CRITICAL MEANINGFUL LEARNING","autores":["Raquel Cordeiro Nogueira Lima","Sylvia De Chiaro"],"autores_todos":["Sylvia De Chiaro","Kátia Aparecida Da Silva Aquino","Raquel Cordeiro Nogueira Lima"],"estudantes":[],"periodico":"DYNAMIS","qualis":"A4","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Aprendizagem Significativa","Pensamento Crítico e Reflexivo","Desenvolvimento e Linguagem","Avaliação e Trajetórias","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.7867/1982-4866.2019v25n3p68-85","doi":"10.7867/1982-4866.2019v25n3p68-85","resumo":"O mapa conceitual é uma ferramenta muito utilizada no contexto educacional para apoiar o estudante na articulação do conhecimento e o professor como instrumento de avaliação. Apoiado em uma concepção de linguagem como constitutiva da cognição, este estudo intenta mostrar que o caráter inerentemente argumentativo que caracteriza a construção dos mapas conceituais contribui para que ele seja um recurso didático privilegiado na aprendizagem significativa crítica. Entendendo a argumentação como caracterizada pela justificação e negociação de perspectivas a partir de uma organização discursiva formada pela relação entre argumento, contra-argumento e resposta, ela tem sido considerada um caminho propício a um funcionamento crítico-reflexivo na construção do conhecimento. Reconhecendo essa movimentação discursiva na construção de mapas conceituais de alunos de química do ensino médio em uma escola pública da região metropoliana do Recife, as análises realizadas mostram portanto, a relação intrínseca que existe entre argumentação e aprendizagem significativa crítica."},{"ano":2019,"titulo":"ANÁLISE DO PROCESSO ARGUMENTATIVO NA CONSTRUÇÃO DE MAPAS CONCEITUAIS E SUAS RELAÇÕES COM A APRENDIZAGEM SIGNIFICATIVA CRÍTICA NO ENSINO DE CIÊNCIAS","autores":"Sylvia De Chiaro","autores_todos":[],"estudantes":[],"periodico":"CIÊNCIA & ENSINO (ONLINE)","qualis":"A2","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Aprendizagem Significativa","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://www.abrapec.com/enpec/xi-enpec/anais/resumos/R2460-1.pdf","doi":"","resumo":""},{"ano":2019,"titulo":"Concepções de Docentes sobre o uso de Metodologias Ativas da Aprendizagem: Um Enfoque na Formação de Enfermeiros","autores":"Kátia Calligaris Rodrigues","autores_todos":["Gésica Kelly Da Silva Oliveira","Kátia Calligaris Rodrigues","Maria Aparecida De Oliveira Freitas"],"estudantes":[],"periodico":"SUSTINERE: REVISTA DE SAÚDE E EDUCAÇÃO","qualis":"A2","area":"Educação","temas":"Pensamento Crítico e Reflexivo","disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.12957/sustinere.2018.36366","doi":"10.12957/sustinere.2018.36366","resumo":"As vertiginosas mudanças na conjuntura social têm posto em reflexão, de maneira contundente, os aspectos relacionados a formação profissional em enfermagem. Assim, esta discussão surge mediante a necessidade de considerar os fatores que são próprios do trabalho em saúde, tais como a relação intrínseca entre as atividades práticas e a teoria, o cuidado holístico, crítico e humanizado, visto que estes elementos são essenciais para o apropriado exercício profissional. Este trabalho objetivou investigar a percepção dos docentes do curso de graduação em enfermagem sobre a utilização e contribuição das metodologias ativas da aprendizagem no processo de formação e desenvolvimento do profissional enfermeiro. Trata-se de um estudo de natureza qualitativa de caráter exploratório-descritivo, que foi realizado com docentes de um Centro Universitário do Agreste Pernambucano. Os dados foram coletados por meio de entrevista semiestruturada, para apreciação dos dados obtidos foirealizada análise de conteúdo, seguindo o referencial teórico proposto por Minayo. Os resultados demonstraram que os docentes compreendem a relevância das metodologias ativas para a formação em enfermagem, entretanto evidenciamos não haver um planejamento de um ensino ativo, pelo professor, demonstrando afinidade com a transmissão de conteúdos, o que sinaliza a importância da atitude reflexiva constante no campo da docência em enfermagem."},{"ano":2019,"titulo":"Education, History and Scientific Culture Research Group","autores":"Kátia Calligaris Rodrigues","autores_todos":"Katia Rodrigues","estudantes":[],"periodico":"CURRÍCULO & DOCÊNCIA","qualis":"B2","area":"Educação","temas":"Ensino de Ciências e Matemática","disciplina":"Ciências (geral)","tipo":"Teórico","idioma":"Inglês","link":"https://periodicos.ufpe.br/revistas/CD/article/download/245925/35265","doi":"","resumo":""},{"ano":2019,"titulo":"El papel de los reguladores semióticos en la construcción y ejecución de un diseño instrucional argumentativo","autores":"Gabriel Fortes","autores_todos":[],"estudantes":[],"periodico":"COGENCY: JOURNAL OF REASONING AND ARGUMENTATION","qualis":"B2","area":"Educação","temas":["Argumentação","Metacognição e Autorregulação","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.32995/cogency.v11i1-2.321","doi":"10.32995/cogency.v11i1-2.321","resumo":"This article investigates how the semiotic tools socially shared have a role in psychological development of students enrolled in argumentative classes. The process of internalization is understood as a form of semiotic regulation, socially shared, that benefits the organization and structuring of higher mental functions. We use an argumentative instructional design inspired by the adaptation made by Leitao (2012) to the Critical Debate Model / MDC (Fuentes, 2011) to create an environment of systematic argumentation as a mediation resource for the development of reflective thinking of students. In each cycle (5 debates), the students (38) are divided into three groups, who rotate to assume the roles of protagonists, antagonistics and judges/researchers – in every cycle there are activities to teach how to argue and argue to learn school content. Hence, they are systematically stimulated to exchange points of view rationally, evaluate arguments, question positions, produce arguments and anticipate counter-arguments. The workshop where teachers stimulated the teaching of argumentation for the purpose of developing argumentative competencies were qualitatively analyzed. The semiotic-discursive analysis of 12 cases (one of the three groups) indicates that there are three levels of regulatory agents: 1) the design, 2) the instruction of the teachers, 3) the reaction (understanding) of the students. And the regulators are divided into the dimensions of knowledge construction and pr"},{"ano":2019,"titulo":"Investigação sobre o desenvolvimento do processo dedutivo nos cursos de Licenciatura em Matemática","autores":"João Carlos Caldato Correia","autores_todos":["Lilian Nasser","João Caldato"],"estudantes":[],"periodico":"REVISTA DE ENSINO DE CIÊNCIAS E MATEMÁTICA (RENCIMA)","qualis":"A1","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Formação de Professores","Desenvolvimento e Linguagem","Avaliação e Trajetórias","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.26843/rencima.v10i2.2333","doi":"10.26843/rencima.v10i2.2333","resumo":"Este artigo relata parte de uma pesquisa que visa investigar se os cursos de Licenciatura em Matemática preparam os futuros professores para explorar, em suas aulas, atividades que promovam o desenvolvimento do pensamento dedutivo. O trabalho foi motivado pela observação de que, em geral, os professores de Matemática não se preocupam em desenvolver a habilidade de argumentação de seus alunos e não valorizam as justificativas informais apresentadas. Esse comportamento pode ser justificado pela formação prévia desses professores. Se o licenciando não teve oportunidade de vivenciar atividades que demandam argumentação ou provas na Escola Básica, é necessário que ele tenha essa experiência durante o curso de formação de professores. No entanto, os resultados de questões discursivas do ENADE que requerem raciocínio dedutivo evidenciam um desempenho preocupante dos licenciandos nesse quesito, pois as médias das notas são, em geral, muito baixas, sendo que a maioria das respostas ficou em branco. Em algumas questões, as respostas apresentadas se baseavam em argumento de natureza empírica, apenas experimentando a validade da afirmativa para poucos exemplos. Os relatórios indicam que os estudantes não encontram nos cursos de graduação em Matemática oportunidades para superarem tais dificuldades."},{"ano":2019,"titulo":"LIBRAS na formação de professores: o vídeo como ferramenta de avaliação da aprendizagem","autores":"Kátia Calligaris Rodrigues","autores_todos":["Thiago Ramos de Albuquerque","Kátia Calligaris Rodrigues","Ernesto Arcenio Valdés Rodriguez"],"estudantes":[],"periodico":"REVISTA EDUCAÇÃO, ARTES E INCLUSÃO","qualis":"A4","area":"Educação","temas":["Metacognição e Autorregulação","Formação de Professores","Avaliação e Trajetórias"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.5965/1984317815012019217","doi":"10.5965/1984317815012019217","resumo":"Este trabalho relata a análise de um conjunto de atividades didáticas de produção de vídeos em Língua Brasileira de Sinais (Libras) por estudantes de cursos de licenciatura do Núcleo de Formação Docente do Centro Acadêmico do Agreste da Universidade Federal de Pernambuco. De forma introdutória, trazemos algumas considerações sobre o lugar da Libras no contexto da educação superior no Brasil. Em seguida tratamos sobre avaliação e autorregulação no processo de ensino-aprendizagem (SILVA, 2007; PERRENOUD, 1999). Finalizando o referencial teórico, discorremos sobre aprendizagem móvel (BOTTENTUIT, 2012; Lévy, 1993). A partir da análise das respostas dos estudantes a um questionário e de dois vídeos produzidos na atividade, observamos que os principais obstáculos para a produção dos vídeos foram: vocabulário incipiente em Libras, a dificuldade em executar as expressões não-manuais e a falta de destreza com a edição dos vídeos. Em conclusão, apontamos que a atividade de produção de vídeos em Libras pode contribuir para uma melhora da prática de sinalização na língua, visto que os alunos são levados a pesquisar previamente os sinais que serão usados para a produção, trabalhando a autorregulação da aprendizagem."},{"ano":2019,"titulo":"NIDEJE SEUS OBJETIVOS E DEMANDAS FRENTE AO CENÁRIO DO USO DE JOGOS DIDÁTICOS NO BRASIL","autores":"Jose Ayron Lira dos Anjos","autores_todos":[],"estudantes":[],"periodico":"CURRÍCULO & DOCÊNCIA","qualis":"B2","area":"Educação","temas":"Metodologias Ativas e Tecnologia","disciplina":[],"tipo":"Teórico","idioma":"Não informado","link":"https://periodicos.ufpe.br/revistas/CD/article/view/245924","doi":"","resumo":""},{"ano":2018,"titulo":"A IMPORTÂNCIA DO MÉTODO: A PESQUISA QUALITATIVA NO AMBIENTE EDUCACIONAL","autores":"Gabriel Fortes","autores_todos":[],"estudantes":[],"periodico":"ARGUMENTOS PRÓ-EDUCAÇÃO - REVISTA DE EDUCAÇÃO DA UNIVÁS","qualis":"Sem Qualis","area":"Educação","temas":"Metodologia de Pesquisa","disciplina":[],"tipo":"Teórico","idioma":"Não informado","link":"https://www.researchgate.net/publication/324629140","doi":"","resumo":""},{"ano":2018,"titulo":"Argumentação e demonstração em matemática: a visão de alunos e professores","autores":"João Carlos Caldato Correia","autores_todos":["João Caldato","Miriam Cardoso Utsumi","Lilian Nasser"],"estudantes":[],"periodico":"REV. TRIANGULO","qualis":"A4","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Formação de Professores","Ensino de Ciências e Matemática"],"disciplina":"Matemática","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.18554/rt.v10i2.2583","doi":"10.18554/rt.v10i2.2583","resumo":"Com o objetivo de investigar a visão de alunos e professores sobre argumentação e demonstração matemática, à luz da tipologia de provas de Balacheff (1988), aplicamos um questionário a professores da Educação Básica do interior do Estado de São Paulo. A partir da análise dos questionários, selecionamos duas turmas do 9º ano do Ensino Fundamental, de professores e escolas públicas distintas que resolveram um teste para avaliar o nível de prova desses alunos. Dentre os resultados obtidos, verificou-se que, em geral, os docentes adotam como sinônimos os termos argumentação, explicação e demonstração, e isto é refletido nas resoluções dos discentes, que apresentam o nível de prova classificado como empirismo ingênuo. Acreditamos que os cursos de licenciatura devem proporcionar aos futuros professores a oportunidade de conceber a argumentação e demonstração como um recurso metodológico a ser utilizado em sala de aula, a fim de criar um ambiente favorável à exploração-investigação da matemática."},{"ano":2018,"titulo":"Considerações sobre uma avaliação diagnóstica do conceito de função à luz da Teoria dos Registros de Representações Semióticas","autores":"Jose Ayron Lira dos Anjos","autores_todos":["Lidiane Pereira Carvalho","José Ayron Lira Dos Anjos","Severino Barros De Melo"],"estudantes":[],"periodico":"REVEMAT","qualis":"A2","area":"Educação","temas":"Avaliação e Trajetórias","disciplina":[],"tipo":"Teórico","idioma":"Português","link":"https://doi.org/10.5007/1981-1322.2017v12n2p116","doi":"10.5007/1981-1322.2017v12n2p116","resumo":"Este trabalho é um recorte de uma pesquisa de mestrado cujo objetivo é elaborar, aplicar e validar uma situação didática para o conceito de função com base na Teoria dos Registros de Representações Semióticas. Este artigo apresenta os resultados das questões em língua natural de uma avaliação diagnóstica realizada com estudantes do 1º ano do Ensino Médio de um Campus do IFPE que foram o público da pesquisa. Os dados foram analisados qualitativamente e apontam que muitos estudantes exigem uma lei algébrica para que uma relação seja função e que as ideias de relação, dependência e variação são as mais presentes na concepção de função desses estudantes."},{"ano":2018,"titulo":"Formando mediadores de argumentação: uma experiência de estágio docência","autores":"Gabriel Fortes","autores_todos":["Gabriel Fortes Macêdo","Nancy Lizeth Ramírez"],"estudantes":[],"periodico":"REVISTA PSICOLOGIA ESCOLAR E EDCUACIONAL","qualis":"A1","area":"Psicologia","temas":["Argumentação","Formação de Professores","Psicologia e Subjetividade","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.1590/2175-35392018038011","doi":"10.1590/2175-35392018038011","resumo":"Resumo Este relato de prática profissional aborda a experiência de estágio docência na formação de monitores para uma disciplina intensamente argumentativa do curso de Psicologia. Esta disciplina é fundada em princípios que visam utilizar a argumentação como auxílio para construção do conhecimento e, também, como forma de incentivo ao desenvolvimento cognitivo dos estudantes envolvidos. Para que esta disciplina seja possível é preciso o treinamento de estudantes para desempenhar o papel de monitor que por um lado participaram ativamente como mediadores da construção do conhecimento e também como aqueles que instauram o discurso argumentativo em sala de aula. Nossa experiência nos diz da importância do treinamento dos monitores como uma forma de incentivar o uso de princípios da psicologia educacional dentro da sala de aula no ensino superior abrindo uma porta para que a sala de aula se torne um ambiente desafiador e propício para o desenvolvimento de habilidades cognitivas."},{"ano":2018,"titulo":"Formação de psicólogos clínicos a partir das atitudes facilitadoras da Abordagem Centrada na Pessoa","autores":"Nádia Oliveira da Silva","autores_todos":[],"estudantes":[],"periodico":"REVISTA CIENTÍFICA E TECNOLÓGICA/FUNDAÇÃO SOUSÂNDRADE DE APOIO AO DESENVOLVIMENTO DA UFMA","qualis":"Sem Qualis","area":"Psicologia","temas":"Psicologia e Subjetividade","disciplina":[],"tipo":"Teórico","idioma":"Não informado","link":"https://scholar.google.com/scholar?q=Forma%C3%A7%C3%A3o%20de%20psic%C3%B3logos%20cl%C3%ADnicos%20a%20partir%20das%20atitudes%20facilitadoras%20da%20Abordagem%20Centrada%20na%20Pessoa","doi":"","resumo":""},{"ano":2018,"titulo":"O IMPACTO DA INTERFACE ENTRE A APRENDIZAGEM BASEADA EM PROBLEMAS E A ARGUMENTAÇÃO NA CONSTRUÇÃO DO CONHECIMENTO CIENTÍFICO","autores":"Sylvia De Chiaro","autores_todos":["Ana Carla Da Silva","Sylvia De Chiaro"],"estudantes":[],"periodico":"INVESTIGAÇÕES EM ENSINO DE CIÊNCIAS (ONLINE)","qualis":"A1","area":"Educação","temas":["Argumentação","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.22600/1518-8795.ienci2018v23n3p82","doi":"10.22600/1518-8795.ienci2018v23n3p82","resumo":"O objetivo do presente trabalho é compreender o impacto que a interface entre a Aprendizagem Baseada em Problemas (ABP) e a argumentação desempenha para a promoção da construção do conhecimento científico. Tomamos como foco de análise, as interações dialógicas entre aluno-aluno e aluno-professor ao longo da resolução de um problema na metodologia ativa ABP, por entendermos que a configuração deste tipo de metodologia favorece o debate crítico e reflexivo de ideias. As análises foram feitas com base na perspectiva da argumentação enquanto mecanismo epistêmico e promotor do pensamento crítico e reflexivo, bem como dos pressupostos sobre os indicadores de alfabetização científica para a promoção da aprendizagem. Nossos resultados apontaram que, embora a metodologia ABP seja propícia ao desenvolvimento de interações dialógicas, por si só, não garante que a argumentação ocorra nem tampouco que os alunos expressem indicadores de alfabetização científica. Concluímos que o desenvolvimento de interações dialógicas depende muito mais do manejo do tutor através de determinadas ações discursivas, as quais fazem toda a diferença quando se pretende utilizar a argumentação para o processo de ensino e de aprendizagem."},{"ano":2017,"titulo":"Aprendizagem Significativa Crítica e Flexibilidade Cognitiva: diálogo metodológico através da construção e validação de uma ferramenta Flexquest para o ensino de Ecologia na educação básica","autores":"José Antônio Bezerra de Oliveira","autores_todos":["José Antônio Bezerra de Oliveira","Cristiane Jussara da Silva","Kátia Aparecida da Silva Aquino"],"estudantes":[],"periodico":"CADERNOS DE ESTUDOS E PESQUISA NA EDUCAÇÃO BÁSICA","qualis":"B2","area":"Educação","temas":["Aprendizagem Significativa","Metodologias Ativas e Tecnologia"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://periodicos.ufpe.br/revistas/cadernoscap/article/download/230849/28800","doi":"","resumo":"A aprendizagem pode se tornar potencialmente significativa quando e possivel alcancar a flexibilizacao do conhecimento por meio de ferramentas didaticas que possam articular varios contextos. Assim, este trabalho teve por objetivo estabelecer um dialogo entre a Teoria da Aprendizagem Significativa Critica e a Teoria da Flexibilidade Cognitiva. Para isso foi desenvolvida uma sequencia didatica para o ensino de Ecologia no Ensino Medio que incluiu, como estrategia, a producao e a aplicacao de uma Flexquest . Os resultados obtidos atraves da analise de mapas conceituais apontam para a reorganizacao das ideias de maneira mais critica e flexivel na estrutura cognitiva dos estudantes. Nesta direcao, e possivel concluir que a flexibilizacao do conhecimento e a utilizacao de ferramentas digitais, em sinergia, fizeram-se potenciais para a promocao de um processo na perspectiva de uma aprendizagem significativa critica."},{"ano":2017,"titulo":"Argumentação na sala de aula e seu potencial metacognitivo como caminho para um enfoque CTS no ensino de química: uma proposta analítica","autores":"Sylvia De Chiaro","autores_todos":["Sylvia De Chiaro","Kátia Aparecida da Silva Aquino"],"estudantes":[],"periodico":"EDUCAÇÃO E PESQUISA","qualis":"A1","area":"Psicologia","temas":["Argumentação","Metacognição e Autorregulação","Metodologias Ativas e Tecnologia","Pensamento Crítico e Reflexivo","Psicologia e Subjetividade","Desenvolvimento e Linguagem","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.1590/s1517-9702201704158018","doi":"10.1590/s1517-9702201704158018","resumo":"Resumo O ensino de química muitas vezes é guiado pela utilização de fórmulas e esquemas, dada a natureza dos símbolos que permeiam tal disciplina. Nesse cenário, são poucos os estudos que tratam de aspectos ligados ao processo de reflexão usando temas na área de ciências exatas. Assim, fazer parte da formação de indivíduos críticos e reflexivos em relação ao conhecimento, a eles mesmos e ao ambiente social e natural em que vivem tem sido preocupação de educadores e psicólogos e está na base do movimento CTS – Ciência, Tecnologia e Sociedade. Este estudo, apoiando-se no potencial metacognitivo da argumentação na educação, amplia essa discussão ao investigar se a utilização desse tipo de discurso propicia aos alunos a reflexão sobre seus próprios pensamentos, mostrando um funcionamento ao nível metacognitivo necessário ao enfoque CTS em sala de aula. Foram analisadas produções textuais de três alunos em aulas de química no ensino médio, nas quais se solicitava o posicionamento destes diante da pergunta “Radioatividade: vida ou morte?”, após serem realizados debates sobre esse tema. As análises mostraram que a argumentação, por sua organização discursiva peculiar, se constitui em interessante alternativa para fazer emergir formas de pensamento sofisticadas, como as que definem um pensamento crítico e reflexivo."},{"ano":2017,"titulo":"CONSTRUÇÃO E ANÁLISE DE MATERIAL INSTRUCIONAL POTENCIALMENTE SIGNIFICATIVO PARA O ENSINO DE QUÍMICA NO ENSINO MÉDIO","autores":["Raquel Cordeiro Nogueira Lima","Sylvia De Chiaro"],"autores_todos":[],"estudantes":[],"periodico":"APRENDIZAGEM SIGNIFICATIVA EM REVISTA","qualis":"C","area":"Ensino (Ciências/Exatas)","temas":"Ensino de Ciências e Matemática","disciplina":"Química","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://www.researchgate.net/publication/331789336","doi":"","resumo":""},{"ano":2017,"titulo":"Elaboração e validação do jogo do palito no ensino de nomenclatura de compostos orgânicos","autores":"Jose Ayron Lira dos Anjos","autores_todos":["José Ayron Lira dos Anjos","Ricardo Lima Guimarães"],"estudantes":[],"periodico":"REVISTA ELETRÔNICA LUDUS SCIENTIAE (RELUS)","qualis":"A3","area":"Ensino (Ciências/Exatas)","temas":["Metodologias Ativas e Tecnologia","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.30691/relus.v1i1.741","doi":"10.30691/relus.v1i1.741","resumo":"O ensino de química orgânica vem sendo pautado na memorização de representações e procedimentos de modo mecânico. Como alternativa, o uso de jogos didáticos vem sendo implementado como estratégias voltadas a um ensino que propicia o protagonismo no processo de ensino-aprendizagem ao aluno. Contudo, faz-se necessário a validação do jogo quanto ao atendimento dos propósitos educacionais e lúdicos, além de garantir que o custo e o tempo de fabricação facilitem sua utilização no ensino básico. Este trabalho apresenta os resultados da validação do Jogo dos Palitos (elaborado pelos autores), bem como o estudo de sua acessibilidade à sala de aula. O Jogo dos Palitos pode ser classificado como uma metodologia de baixo custo e que não requer tempo algum para preparo. Do ponto de vista da validação, constatou-se seu êxito na aprendizagem do procedimento de elaborar cadeias carbônicas utilizando fórmula de linhas de ligação, bem como em aplicar as regras da IUPAC para nomear estruturas orgânicas."},{"ano":2017,"titulo":"SISTEMATIZAÇÃO DA AVALIAÇÃO DO ENSINO: UMA PROPOSTA FUNDAMENTADA A LUZ DO PROCESSO DE ENFERMAGEM","autores":"Kátia Calligaris Rodrigues","autores_todos":["Gleidson Monteiro Dos Santos","Gésica Kelly Da Silva Oliveira","Gidelson Gabriel Gomes","Kátia Silva Cunha","Kátia Calligaris Rodrigues"],"estudantes":[],"periodico":"REVISTA CONTEXTO & SAÚDE","qualis":"A4","area":"Educação","temas":["Metacognição e Autorregulação","Avaliação e Trajetórias"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.21527/2176-7114.2017.33.174-185","doi":"10.21527/2176-7114.2017.33.174-185","resumo":"&lt;p&gt;Considerando a perspectiva de ensinar/aprender/avaliar como processo relacional com o mundo, faz necessário que os docentes pensem em novas e diversas estratégias para ensinar e analisar. Nesta vertente, este estudo objetiva propor um modelo de avaliação do ensino de forma sistematizada, com base no Processo de Enfermagem (PE). Para fomentar este estudo, foi realizada uma revisão da literatura. A Sistematização da Avaliação do Ensino (SAE) sugerida vem se estabelecer como um método que visa a substanciar o olhar docente pela ótica da integralidade em que cada aluno se insere na conjuntura educativa. Contempla cinco etapas inter-relacionadas: Histórico do aluno, avaliação diagnóstica, planejamento das estratégias de ensino, implementação das estratégias de ensino e avaliação da aprendizagem. A autorregulação ainda se constitui um desafio à prática docente, pois se refere a um processo de avaliação das situações de aprendizagem utilizado para direcionar a construção dos saberes. A SAE, proposta neste estudo, contempla uma avaliação que direciona um ensino significativo ao aluno contribuindo para um processo relacional de ensino e aprendizagem emancipatória.&lt;/p&gt;"},{"ano":2016,"titulo":"A IMPLICAÇÃO DAS EMOÇÕES NO INÍCIO DA VIVÊNCIA HOSPITALAR EM GRADUANDOS DE ENFERMAGEM","autores":"Gabriel Fortes","autores_todos":["Mara Cristina Ribeiro","Rebeca de Oliveira Lessa","Gabriel Fortes"],"estudantes":[],"periodico":"PSICOLOGIA & SABERES","qualis":"A4","area":"Educação","temas":["Psicologia e Subjetividade","Políticas e Equidade Educacional"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.3333/ps.v5i6.764","doi":"10.3333/ps.v5i6.764","resumo":"O ensino pratico assistencial no curriculo de enfermagem e de extrema importância por apresentar ao discente a realidade profissional. A formacao pretende garantir a capacitacao dos academicos em relacao a autonomia e discernimento para assegurar a integralidade e a humanizacao da assistencia. Assim, e necessario discutir o estado emocional do academico, dentro e fora do ambiente hospitalar. O estudo pretendeu descrever a implicacao do inicio da vivencia hospitalar no surgimento de emocoes conflitantes em graduandos de enfermagem. Trata-se de estudo qualitativo, exploratorio e de campo que desenvolveu 10 entrevistas semiestruturada com academicos do curso de enfermagem de uma universidade publica. As falas foram analisadas e interpretadas por meio da Analise Tematica. Os resultados apontam que as primeiras experiencias praticas no campo hospitalar provocam uma serie de emocoes que pode beneficiar a formacao do discente ou prejudica-la. A forma de lidar como este aspecto pelo estudante, pelos docentes e pela instituicao de ensino aparece como fator essencial na formacao de profissionais mais bem preparados. Conclui-se que o aprofundamento de estudos dessa tematica pode possibilitar a criacao de estrategias que transformem situacoes negativas detectadas em possibilidades de qualificacao do processo ensino-aprendizagem."},{"ano":2016,"titulo":"El debate crítico","autores":"Sylvia De Chiaro","autores_todos":[],"estudantes":[],"periodico":"TEXTOS DE DIDACTICA DE LA LENGUA Y DE LA LITERATURA","qualis":"Sem Qualis","area":"Educação","temas":"Argumentação","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://www.researchgate.net/publication/314998950","doi":"","resumo":""},{"ano":2016,"titulo":"Narrando o tempo/vida: reflexões teóricas sobre a experiência discursiva de ser e estar na linguagem","autores":"Gabriel Fortes","autores_todos":"Gabriel Fortes","estudantes":[],"periodico":"TRAVESSIAS (UNIOESTE. ONLINE)","qualis":"A4","area":"Psicologia","temas":["Psicologia e Subjetividade","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://dialnet.unirioja.es/descarga/articulo/8093212.pdf","doi":"","resumo":"On the present paper it is briefly introduced the culturalistic perspective and its relevance towards the studies in Psychology, taking its historical dimension and also its mains characters who legitimated the linguistic turn into the psychological studies, I do not intend an exhaustive revision, but actually, define the horizons of the field. Using as an example it will be analyzed the discursive markers in the Portuguese Fado entitled “Vida vivida” [lived life] from Argentina Santos, discussing the subjective life materiality and the potential of artistic creation as analogous to real life subjectivity. It is seem that the uses of determined linguistic markers enables not only the textual construction (syntax and semantics relations), but also, the ways a person organize its own life (psychological subjective experience), as so, the social practices enabled by discursive organization (in pragmatic level), constituting one’s own life plot (as the textuality of human experience) as a form of self-narrative. Arguing, from the analyzed example, the importance of the experiential dimension of human life lived through language (as a poetic dimension of experience), and, perhaps, neglected in some perspectives of contemporary Psychology. It is also discussed the relevance of studying narratives in psychology, since it (the narrative) allows us construct realities, make sense and experience subjective life."},{"ano":2016,"titulo":"O JOGO DAS REAÇÕES ORGÂNICAS: UM CAMINHO PARA REELABORAÇÃO DO CONHECIMENTO A PARTIR DO ERRO","autores":"Jose Ayron Lira dos Anjos","autores_todos":[],"estudantes":[],"periodico":"REVISTA DEBATES EM ENSINO DE QUÍMICA","qualis":"A1","area":"Educação","temas":["Metodologias Ativas e Tecnologia","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://www.journals.ufrpe.br/index.php/REDEQUIM/article/view/1294/1054","doi":"","resumo":""},{"ano":2015,"titulo":"A experiência da unidade espaço-tempo na literatura e na psicologia","autores":"Gabriel Fortes","autores_todos":["Gabriel Fortes","Nadja Maria Vieira"],"estudantes":[],"periodico":"BAKHTINIANA - REVISTA DE ESTUDOS DO DISCURSO","qualis":"A1","area":"Psicologia","temas":"Psicologia e Subjetividade","disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doi.org/10.1590/2176-457320791","doi":"10.1590/2176-457320791","resumo":"RESUMONeste ensaio defende-se o argumento de que a configuração cronotópica potencializa a obra literária como forma metafórica para experimentar a vida cotidiana. Esse argumento apoia-se nas declarações em que Bakhtin destacou que a organização de processos psicológicos de personagens no enredo está relacionada com a experiência da unidade tempo-espaço, conceitualmente denominada de cronotopo. Para exemplificar essas questões desenvolveu-se aqui uma análise da configuração cronotópica do autor-personagem no Livro do desassossego de Fernando Pessoa. A dificuldade do autor-personagem para negociar as posições de figura e fundo no seu pensamento refletiu uma experiência de fronteira específica, revelada na frequente associação de termos antagônicos e uso frequente de neologismos. Percebendo o funcionamento cronotópico da narrativa, discute-se o potencial da literatura na provisão de metáforas para vida real. Nessas considerações chamou-se a atenção para a participação do leitor na constituição do cronotopo e da obra."},{"ano":2015,"titulo":"Análise da produção argumentativa em redações de jovens pré-acadêmicos","autores":"Sylvia De Chiaro","autores_todos":["Jaime Luiz do Nascimento","Sylvia De Chiaro"],"estudantes":"Jaime Luiz Bezerra do Nascimento","periodico":"TÓPICOS EDUCACIONAIS","qualis":"B4","area":"Educação","temas":["Argumentação","Pensamento Crítico e Reflexivo"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://doaj.org/article/398b2aaecc594fbaa679635bd988a9a0","doi":"","resumo":"\"Este artigo apresenta aspectos de um estudo sobre a aprendizagem do texto dissertativo-argumentativo no eixo de produção escrita em língua portuguesa. Partindo de uma perspectiva dialógica de argumentação e entendendo-a como composta por argumento, contra-argumento e resposta, textos produzidos por jovens pré-acadêmicos no treino para o ENEM foram analisados. As análises mostraram que os textos buscaram atender às exigências do gênero, especialmente selecionando argumentos e propondo respostas à questão temática, mas nem sempre apresentando contraposições. Foi possível perceber, no entanto, que quando antecipa contra-argumentos, negociando perspectivas, o texto ganha em qualidade argumentativa e em sofisticação nas propostas de intervenção, o que levou à conclusão do quanto a compreensão e exercício da estrutura composta por argumento, contra-argumento e resposta poderia trazer ganhos qualitativos nessa produção e consequentemente na capacidade reflexiva dos alunos.\""},{"ano":2015,"titulo":"Construção de sentidos na escolha profissional de jovens: reflexões a partir da perspectiva sócio-histórica","autores":"Sylvia De Chiaro","autores_todos":["Thayane Maria Deodato Cavalcante","Sylvia De Chiaro","Carlos Eduardo Ferreira Monteiro"],"estudantes":[],"periodico":"TEMA: REVISTA ELETRÔNICA DE CIÊNCIAS","qualis":"A3","area":"Psicologia","temas":["Pensamento Crítico e Reflexivo","Psicologia e Subjetividade"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"http://revistatema.facisa.edu.br/index.php/revistatema/article/viewFile/253/pdf","doi":"","resumo":"Perspectivas socio-historicas da Psicologia postulam que a atividade humana e capaz de emancipar o individuo criando possibilidades de desenvolvimento pessoal e contribuindo para a transformacao positiva da sociedade. Entretanto, ao mesmo tempo em que edifica o individuo, as acoes humanas podem, inversamente, dificultar a negociacao de significados e gerar alienacao em lugar da conscientizacao. Este artigo tem como objetivo discutir aspectos da construcao de sentidos gerados a partir das escolhas profissionais de jovens de um municipio da Zona da Mata de Pernambuco, Brasil. Coletaram-se os dados da pesquisa utilizando a tecnica de grupo focal e a partir da producao de um texto escrito pelos participantes. As analises dos resultados sugerem que os discursos dos estudantes carregam varios sentidos produzidos que determinam o momento da escolha profissional, levando-os, em sua maioria, a reproduzir um modelo de discurso e de atividade que acaba por dificultar os processos de constituicao enquanto individuos criticos e reflexivos. Conclui-se que e necessario tornar a escola um espaco de reflexao, onde esses jovens possam ter acesso a informacoes e discutir criticamente sobre a imposicao de sentidos hegemonicos, para alargar suas possibilidades e potencializar oportunidades de realizacao profissional."},{"ano":2015,"titulo":"Herbivoria em Dalbergia ecastophyllum em área de restinga do Norte de Pernambuco, Brasil","autores":"José Antônio Bezerra de Oliveira","autores_todos":[],"estudantes":[],"periodico":"NATUREZA ON LINE (ESPÍRITO SANTO)","qualis":"C","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://naturezaonline.com.br/revista/article/view/170","doi":"","resumo":""},{"ano":2014,"titulo":"Bivalves oriundos de ecossistemas locais comercializados no Litoral Norte de Pernambuco, Brasil","autores":"José Antônio Bezerra de Oliveira","autores_todos":["Andreza Ximenes de Arajo","Jos Antnio Bezerra de Oliveira"],"estudantes":[],"periodico":"EDUCAÇÃO AMBIENTAL EM AÇÃO","qualis":"Sem Qualis","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Português","link":"https://www.revistaea.org/artigo.php?idartigo=1901","doi":"","resumo":"A classe Bivalvia compreende moluscos de corpo achatado lateralmente que possuem concha calc�ria formada por duas valvas que protegem a massa visceral"},{"ano":2014,"titulo":"O desenvolvimento metacognitivo em situação de argumentação no ensino de química","autores":"Sylvia De Chiaro","autores_todos":[],"estudantes":[],"periodico":"REVISTA DE EDUCACION DE LAS CIENCIAS","qualis":"B1","area":"Ensino (Ciências/Exatas)","temas":["Argumentação","Metacognição e Autorregulação","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Não informado","link":"https://scholar.google.com/scholar?q=O%20desenvolvimento%20metacognitivo%20em%20situa%C3%A7%C3%A3o%20de%20argumenta%C3%A7%C3%A3o%20no%20ensino%20de%20qu%C3%ADmica","doi":"","resumo":""},{"ano":2014,"titulo":"Pesquisador e professor um caso a ser contado","autores":"Valter Cesar Montanher","autores_todos":"Valter César Montanher","estudantes":[],"periodico":"CIÊNCIA & ENSINO (ONLINE)","qualis":"A2","area":"Educação","temas":"Ensino de Ciências e Matemática","disciplina":"Ciências (geral)","tipo":"Empírico/Prático","idioma":"Português","link":"http://prc.ifsp.edu.br/ojs/index.php/cienciaeensino/article/view/895","doi":"","resumo":""},{"ano":2013,"titulo":"Investindo na formação inicial do professor - pesquisador: Reflexão e mudança na formação do professor de ciências","autores":["Jose Ayron Lira dos Anjos","Kátia Calligaris Rodrigues"],"autores_todos":[],"estudantes":[],"periodico":"CADERNOS DE PEDAGOGIA NO ENSINO SUPERIOR","qualis":"Sem Qualis","area":"Educação","temas":"Formação de Professores","disciplina":[],"tipo":"Teórico","idioma":"Não informado","link":"https://scholar.google.com/scholar?q=Investindo%20na%20forma%C3%A7%C3%A3o%20inicial%20do%20professor%20-%20pesquisador%3A%20Reflex%C3%A3o%20e%20mudan%C3%A7a%20na%20forma%C3%A7%C3%A3o%20do%20professor%20de%20ci%C3%AAncias","doi":"","resumo":""},{"ano":2013,"titulo":"Uso de mapas conceituais: percepções sobre a construção de conhecimentos de estudantes do ensino médio a respeito do tema radioatividade","autores":"Sylvia De Chiaro","autores_todos":["Kátia Aparecida da Silva Aquino","Sylvia De Chiaro"],"estudantes":[],"periodico":"CIÊNCIAS & COGNIÇÃO (UFRJ)","qualis":"A4","area":"Ensino (Ciências/Exatas)","temas":["Aprendizagem Significativa","Ensino de Ciências e Matemática"],"disciplina":"Química","tipo":"Empírico/Prático","idioma":"Português","link":"https://cienciasecognicao.tempsite.ws/revista/index.php/cec/article/view/854","doi":"","resumo":"RESUMO ESTE TRABALHO DESTINA-SE A INVESTIGAR AS CONTRIBUICOES DOS MAPAS CONCEITUAIS NA ANALISE DA CONSTRUCAO DO CONHECIMENTO RELACIONADO AO TEMA RADIOATIVIDADE NO ENSINO DE QUIMICA COM ESTUDANTES DO TERCEIRO ANO DO ENSINO MEDIO, TENDO COMO PARADIGMA TEORICO A APRENDIZAGEM SIGNIFICATIVA DE DAVID AUSUBEL. TAL TEORIA COMPREENDE QUE O APRENDIZ SE APROPRIA DO CONHECIMENTO, POR ELABORACAO PESSOAL, A PARTIR DE CONCEITOS PRE-EXISTENTES EM SUA ESTRUTURA COGNITIVA, QUE VAO SE MODELANDO E SE APRIMORANDO POR DIFERENCIACAO PROGRESSIVA E/OU RECONCILIACAO INTEGRATIVA NO DECORRER DO PROCESSO DE ENSINO E APRENDIZAGEM. PARTINDO DESSA TEORIA, JOSEPH NOVAK DESENVOLVEU A METODOLOGIA DE MAPAS CONCEITUAIS, NO SENTIDO DE REPRESENTAR COMO O CONHECIMENTO E ARMAZENADO NA ESTRUTURA COGNITIVA DE UM ESTUDANTE. UTILIZANDO COMO CATEGORIAS DE ANALISE A DIFERENCIACAO PROGRESSIVA E A RECONCILIACAO INTEGRATIVA, MAPAS CONCEITUAIS DE DOIS ESTUDANTES, ANTES E DEPOIS DA REFERIDA UNIDADE TEMATICA, SAO ESTUDADOS PARA A COMPREENSAO DA ORGANIZACAO CONCEITUAL QUE OS ESTUDANTES ATRIBUIRAM AO TEMA. AS ANALISES MOSTRAM QUE OS MAPAS CONCEITUAIS CONSTITUEM-SE EM RECURSO PRIVILEGIADO DE ACOMPANHAMENTO DO PROCESSO ENSINO E APRENDIZAGEM DOS ESTUDANTES POR SEUS EDUCADORES. PALAVRAS-CHAVE : MAPAS CONCEITUAIS; RADIOATIVIDADE; ENSINO DE QUIMICA; DIFERENCIACAO PROGRESSIVA; RECONCILIACAO INTEGRATIVA ABSTRACT THIS STUDY AIMS TO INVESTIGATE THE CONTRIBUTIONS OF CONCEPTUAL MAPS IN THE ANALYSIS OF THE CONSTRUCTION OF KNOWLEDGE RELATED TO"},{"ano":2012,"titulo":"Characterization of aortic valve stenosis by mathematical modelling of the reflectance spectroscopy","autores":"Kátia Calligaris Rodrigues","autores_todos":["Katia C. Rodrigues","Renato A. Zângaro","Adriano O. Andrade","Marcio Magini"],"estudantes":[],"periodico":"JOURNAL OF BIOMEDICAL GRAPHICS AND COMPUTING","qualis":"Sem Qualis","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.5430/jbgc.v2n2p48","doi":"10.5430/jbgc.v2n2p48","resumo":"Background: The stenosis of the aortic valve is a consequence of an increased thickness and disorganization of the collagen fibre network and extracellular matrix, plus the deposits of calcification in the layers of the valve. These characteristics are known to affect the diffuse spectral reflectance of the tissue. Objective: The main focus of this work is to propose a model for the aortic valve reflectance whose parameters can be employed as features capable of discriminating distinct levels of tissue thickness and disorganization. Methods: The data obtained from aortic valve reflectance show a S-type curve. Therefore, the modeling hypothesis is that the aortic valve stenosis generates a sigmoidal behavior at the reflectance spectroscopy. The mathematical modeling was obtained by a sigmoidal approaching and Euler methodology applied. Results: The results show the successful application of the model in the investigation of heart valve tissues with distinct characteristics. Conclusion: The solutions of this equation define parameters that can be interpreted quantitatively helping to discriminate the stenosis process in aortic valve predictable for different cases proposed in this study."},{"ano":2012,"titulo":"Glicemical Analysis of Human Blood Serum Using FT-Raman: A New Approach","autores":"Kátia Calligaris Rodrigues","autores_todos":["Jamil Saade","Josivandro do Nascimento Silva","Patrícia M. Albuquerque de Farias","Daniela Franco Lopes","Cássio Tristão dos Santos","Bruno de Araújo Farias","Kátia Calligaris Rodrigues","Airton Abrahão Martin"],"estudantes":[],"periodico":"PHOTOMEDICINE AND LASER SURGERY","qualis":"B4","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1089/pho.2012.3238","doi":"10.1089/pho.2012.3238","resumo":"BACKGROUND DATA: Fourier transform Raman spectroscopy (FT-Raman) is a noninvasive diagnostic tool largely applied to the analysis of biological fluids and tissues. METHODS: We examined the variation of carbohydrate concentration in human blood during 180 min relative to 29 spectra of patients split into four categories: hypoglycemic, healthy, threshold, and diabetic. The main bands monitored were placed in 960, 1030, 1091, 1128, and 1205 cm(-1). These bands were respectively attributed to C-O, C-C (stretching), C-O-H and C-O-C of carbohydrates. In this study, the Raman scattering signal of the all the blood samples was collected during 360 sec. The calculated correlation coefficient (R) between the concentration of carbohydrates and the Raman intensity was 0.923. CONCLUSIONS: The obtained results are reasonable according to classical biochemical analysis. Our proposed FT-Raman-based method was shown to be suitable for the monitoring of carbohydrate concentration in human blood, and presented some advantages over classical biochemical methods, such as real-time analysis, required small sample volume, and was nondestructive, and the samples did not need any previous treatment."},{"ano":2012,"titulo":"Radical intermediates in the Zn-promoted Barbier-type alkylation of diphenyl diselenide in aqueous medium","autores":"Jose Ayron Lira dos Anjos","autores_todos":["José Ayron Lira dos Anjos","Lothar Wilhelm Bieber"],"estudantes":[],"periodico":"TETRAHEDRON LETTERS","qualis":"B1","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1016/j.tetlet.2012.09.063","doi":"10.1016/j.tetlet.2012.09.063","resumo":""},{"ano":2012,"titulo":"Óleo residual de frituras: uma abordagem interdisciplinar na perspectiva da educação ambiental na educação básica","autores":"José Antônio Bezerra de Oliveira","autores_todos":[],"estudantes":[],"periodico":"EDUCAÇÃO AMBIENTAL EM AÇÃO","qualis":"Sem Qualis","area":"Educação","temas":"Educação Ambiental","disciplina":[],"tipo":"Empírico/Prático","idioma":"Não informado","link":"https://www.revistaea.org/artigo.php?idartigo=1371","doi":"","resumo":""},{"ano":2009,"titulo":"Optimizing the Raman signal for characterizing organic samples: The effect of slit aperture and exposure time","autores":"Kátia Calligaris Rodrigues","autores_todos":["João Carlos Lázaro","Marcos Tadeu T. Pacheco","Kátia Calligaris Rodrigues","Carlos José de Lima","Leonardo Marmo Moreira","Antonio Balbin Villaverde","Landulfo Silveira Jr."],"estudantes":[],"periodico":"SPECTROSCOPY (OTTAWA)","qualis":"Sem Qualis","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1155/2009/764524","doi":"10.1155/2009/764524","resumo":"The present work is focused on the influence of the slit aperture and time exposure of the infrared light on the Charge Coupled Device (CCD) in relation to their physical effects, in order to improve the Raman spectrum characteristics. Indeed, the alterations in slit aperture and CCD time exposure affect significantly important spectral properties, such as the spectral intensity, Signal to Noise Ratio (SNR) and band width resolution of the Raman spectra. Therefore, the present proposal has the aim of to found the optimum conditions of instrumental arrangement, involving the minimum collection time and maximum signal quality in dispersive Raman spectrometers. Samples of dehydrated human teeth and naphthalene were evaluated with a Raman dispersive spectrometer employing excitation wavelength of 830 nm in several integration times and spectrometer slit apertures. The analysis of the spectral intensity, SNR and band width of selected Raman peaks allowed to infer that these properties of a dispersive Raman spectrum depend directly of the exposure time on the detector as well as spectrograph slit aperture. It is important to register that the higher SNR was obtained with higher exposure time intervals. To the samples evaluated in the present article, the band width has lower values for slit apertures of 100–150 μm, i.e., in this aperture range the spectral resolution is maximum. On the publisher-id hand, the intensity and SNR of the Raman spectra becomes optimal for slit apertures"},{"ano":2008,"titulo":"Fluorescence and Reflectance Spectroscopy for Identification of Atherosclerosis in Human Carotid Arteries Using Principal Components Analysis.","autores":"Kátia Calligaris Rodrigues","autores_todos":["Rick Rocha","Antonio Balbin Villaverde","Landulfo Silveira","Aldo Brugnera","Leandro Procópio Alves","Egberto Munin","Kátia Calligaris Rodrigues","Carlos Augusto Pasqualucci","Marcos Tadeu Tavares Pacheco"],"estudantes":[],"periodico":"PHOTOMEDICINE AND LASER SURGERY","qualis":"B4","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1089/pho.2007.2208","doi":"10.1089/pho.2007.2208","resumo":"OBJECTIVES: The aim of this work was to verify the differentiation between normal and pathological human carotid artery tissues by using fluorescence and reflectance spectroscopy in the 400- to 700-nm range and the spectral characterization by means of principal components analysis. BACKGROUND DATA: Atherosclerosis is the most common and serious pathology of the cardiovascular system. Principal components represent the main spectral characteristics that occur within the spectral data and could be used for tissue classification. MATERIALS AND METHODS: Sixty postmortem carotid artery fragments (26 non-atherosclerotic and 34 atherosclerotic with non-calcified plaques) were studied. The excitation radiation consisted of a 488-nm argon laser. Two 600-microm core optical fibers were used, one for excitation and one to collect the fluorescence radiation from the samples. The reflectance system was composed of a halogen lamp coupled to an excitation fiber positioned in one of the ports of an integrating sphere that delivered 5 mW to the sample. The photo-reflectance signal was coupled to a (1/4)-m spectrograph via an optical fiber. Euclidean distance was then used to classify each principal component score into one of two classes, normal and atherosclerotic tissue, for both fluorescence and reflectance. RESULTS: The principal components analysis allowed classification of the samples with 81% sensitivity and 88% specificity for fluorescence, and 81% sensitivity and 91% specificity for"},{"ano":2007,"titulo":"Effect of hydroalcoholic extract of Zingiber officinalis rhizomes on LPS-induced rat airway hyperreactivity and lung inflammation","autores":"Kátia Calligaris Rodrigues","autores_todos":["F. Aimbire","S.C. Penna","M. Rodrigues","K.C. Rodrigues","R.A.B. Lopes-Martins","J.A.A. Sertié"],"estudantes":[],"periodico":"PROSTAGLANDINS, LEUKOTRIENES AND ESSENTIAL FATTY ACIDS","qualis":"A3","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1016/j.plefa.2007.08.008","doi":"10.1016/j.plefa.2007.08.008","resumo":""},{"ano":2005,"titulo":"O papel do professor na construção discursiva da argumentação em sala de aula","autores":"Sylvia De Chiaro","autores_todos":["Sylvia De Chiaro","Selma Leitão"],"estudantes":[],"periodico":"PSICOLOGIA: REFLEXÃO E CRÍTICA (UFRGS. IMPRESSO)","qualis":"A1","area":"Educação","temas":["Argumentação","Desenvolvimento e Linguagem"],"disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1590/s0102-79722005000300009","doi":"10.1590/s0102-79722005000300009","resumo":"A natureza canônica dos referentes do discurso de sala de aula, a relação assimétrica professor-aluno e a previsibilidade dos resultados das discussões parecem tornar a sala de aula um espaço pouco propício à argumentação. Entretanto, reconhecendo a importância desta como recurso didático, o presente artigo discute sua construção em situações instrucionais. A tese central é que ações discursivas, nos planos pragmático, argumentativo e epistêmico, implementam a argumentação em sala de aula. Dois grupos de discussão da quinta série são analisados, um gerido pelos alunos e outro mediado pela professora. Os resultados mostram que ações facilitadoras da emergência e sustentação da argumentação surgem nos dois grupos, porém, ações que aproximam as conclusões dos alunos do conhecimento convencionalizado dependem prioritariamente da mediação da professora."},{"ano":2003,"titulo":"Reductive Coupling Reaction of Benzil, Allyl and Alkyl Halides in Aqueous Medium Promoted by Zinc","autores":"Jose Ayron Lira dos Anjos","autores_todos":["Ana C. P. F. de Sá","Giovanna M. A. Pontes","José A. L. dos Anjos","Sidney R. Santana","Lothar W. Bieber","Ivani Malvestiti"],"estudantes":[],"periodico":"JOURNAL OF BRAZILIAN CHEMICAL SOCIETY","qualis":"Sem Qualis","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1590/s0103-50532003000300015","doi":"10.1590/s0103-50532003000300015","resumo":"Organic halides undergo reductive dimerization (Wurtz-type coupling) promoted by zinc at room temperature in aqueous medium. The reaction yields are strongly enhanced by copper catalysis. This coupling procedure provides an efficient and simple method for the homocoupling of benzylic and allylic bromides and primary alkyl iodides."},{"ano":2003,"titulo":"Using the laser-induced fluorescence spectroscopy in the differentiation between normal and neoplastic human breast tissue","autores":"Kátia Calligaris Rodrigues","autores_todos":["R. Hage","P. R. Galhanone","R. A. Z�ngaro","K. C. Rodrigues","M. T. T. Pacheco","A. A. Martin","M. M. Netto","F. A. Soares","I. W. da Cunha"],"estudantes":[],"periodico":"LASERS IN MEDICAL SCIENCE","qualis":"A2","area":"Outras produções científicas","temas":"Outras produções científicas","disciplina":[],"tipo":"Empírico/Prático","idioma":"Inglês","link":"https://doi.org/10.1007/s10103-003-0271-9","doi":"10.1007/s10103-003-0271-9","resumo":""}];

